{
  "name": "LuminaConfig - 3D Magnetic Track Lighting Configurator",
  "description": "A high-end 3D configurator for professional magnetic track lighting systems, featuring real-time pricing and modular layouts."
}

export enum LayoutType {
  LINEAR = 'LINEAR',
  RECTANGULAR = 'RECTANGULAR'
}

export enum LampType {
  SPOT_DIRECTIONAL = 'SPOT_DIRECTIONAL',
  FIXED_RACK = 'FIXED_RACK'
}

export interface PlacedLamp {
  id: string;
  type: LampType;
  trackIndex: number; // 0-3 for rectangular, 0 for linear
  position: number;   // 0 to 1 along the track segment
}

export interface ConfigState {
  layout: LayoutType;
  width: number;
  depth: number;
  ceilingHeight: number;
  suspensionHeight: number;
  lamps: PlacedLamp[];
}

export const PRICING = {
  RAIL_KIT_2M: 70,
  SPOT_DIRECTIONAL: 33,
  FIXED_RACK: 60
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useCallback } from 'react';
import { Scene3D } from './components/Scene3D';
import { Sidebar } from './components/Sidebar';
import { ConfigState, LayoutType, PlacedLamp, PRICING, LampType } from './types';

const App: React.FC = () => {
  const [config, setConfig] = useState<ConfigState>({
    layout: LayoutType.LINEAR,
    width: 3,
    depth: 2,
    ceilingHeight: 3.5,
    suspensionHeight: 0.8,
    lamps: []
  });

  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);

  const calculateTotal = useMemo(() => {
    let railSegments = 0;
    if (config.layout === LayoutType.LINEAR) {
      railSegments = Math.ceil(config.width / 2);
    } else {
      railSegments = Math.ceil((config.width * 2 + config.depth * 2) / 2);
    }

    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const lampsCost = config.lamps.reduce((acc, lamp) => {
      return acc + (lamp.type === LampType.SPOT_DIRECTIONAL ? PRICING.SPOT_DIRECTIONAL : PRICING.FIXED_RACK);
    }, 0);

    return railCost + lampsCost;
  }, [config]);

  const addLamp = useCallback((type: LampType, trackIndex: number, position: number) => {
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      trackIndex,
      position
    };
    setConfig(prev => ({
      ...prev,
      lamps: [...prev.lamps, newLamp]
    }));
  }, []);

  const removeLamp = useCallback((id: string) => {
    setConfig(prev => ({
      ...prev,
      lamps: prev.lamps.filter(l => l.id !== id)
    }));
  }, []);

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden">
      {/* 3D Viewport */}
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          onCancelPlacement={() => setActiveLampType(null)}
        />

        {/* Floating Scale Indicator */}
        <div className="absolute bottom-6 left-6 text-[10px] uppercase tracking-widest text-gray-400 pointer-events-none">
          1:1 Scale Preview | {config.layout} | {config.width.toFixed(1)}m x {config.layout === 'LINEAR' ? '0.0' : config.depth.toFixed(1)}m
        </div>
      </div>

      {/* Control Sidebar */}
      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        totalPrice={calculateTotal}
        activeLampType={activeLampType}
        setActiveLampType={setActiveLampType}
      />
    </div>
  );
};

export default App;

import React, { Suspense, useRef, useState } from 'react';
import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment, Grid, ContactShadows } from '@react-three/drei';
import * as THREE from 'three';
import { ConfigState, LampType, LayoutType, PlacedLamp } from '../types';
import { HumanScale } from './HumanScale';
import { TrackSystem } from './TrackSystem';

interface Scene3DProps {
  config: ConfigState;
  activeLampType: LampType | null;
  onPlaceLamp: (type: LampType, trackIndex: number, position: number) => void;
  onRemoveLamp: (id: string) => void;
  onCancelPlacement: () => void;
}

export const Scene3D: React.FC<Scene3DProps> = ({ 
  config, 
  activeLampType, 
  onPlaceLamp, 
  onRemoveLamp,
  onCancelPlacement 
}) => {
  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);

  const handleTrackHover = (index: number, point: THREE.Vector3) => {
    if (!activeLampType) return;

    // Calculate normalized position (0 to 1) along the track segment
    // This is a simplified calculation based on the layout logic
    let pos = 0;
    if (config.layout === LayoutType.LINEAR) {
      pos = (point.x + config.width / 2) / config.width;
    } else {
      // Logic for rectangular sides
      if (index === 0 || index === 2) {
        pos = (point.x + config.width / 2) / config.width;
      } else {
        pos = (point.z + config.depth / 2) / config.depth;
      }
    }
    setHoveredTrack({ index, pos: Math.max(0, Math.min(1, pos)) });
  };

  const handleTrackClick = (e: ThreeEvent<MouseEvent>, index: number) => {
    if (activeLampType && hoveredTrack) {
      onPlaceLamp(activeLampType, index, hoveredTrack.pos);
      onCancelPlacement();
    }
    e.stopPropagation();
  };

  return (
    <Canvas shadows className="w-full h-full">
      <PerspectiveCamera makeDefault position={[5, 4, 8]} fov={45} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 1.8} 
        enableDamping 
        makeDefault
      />

      <ambientLight intensity={0.5} />
      <spotLight position={[10, 10, 10]} angle={0.15} penumbra={1} intensity={1} castShadow />
      <pointLight position={[-10, -10, -10]} intensity={0.5} />

      <Suspense fallback={null}>
        <Environment preset="city" />

        {/* Ceiling */}
        <mesh position={[0, config.ceilingHeight, 0]} rotation={[Math.PI / 2, 0, 0]} receiveShadow>
          <planeGeometry args={[20, 20]} />
          <meshStandardMaterial color="#ffffff" />
        </mesh>

        {/* Floor & Grid */}
        <Grid 
          infiniteGrid 
          fadeDistance={20} 
          fadeStrength={5} 
          sectionSize={1} 
          sectionColor="#e5e7eb" 
          cellSize={0.2} 
          cellColor="#f3f4f6"
        />
        <mesh rotation={[-Math.PI / 2, 0, 0]} position={[0, -0.01, 0]} receiveShadow>
          <planeGeometry args={[100, 100]} />
          <shadowMaterial transparent opacity={0.2} />
        </mesh>

        {/* Human Scale Reference */}
        <HumanScale position={[2, 0, 2]} />

        {/* Track Lighting System */}
        <TrackSystem 
          config={config} 
          onTrackHover={handleTrackHover}
          onTrackClick={handleTrackClick}
          hoveredInfo={hoveredTrack}
          activeLampType={activeLampType}
          onRemoveLamp={onRemoveLamp}
        />

        <ContactShadows 
          position={[0, 0, 0]} 
          opacity={0.4} 
          scale={20} 
          blur={2} 
          far={4.5} 
        />
      </Suspense>
    </Canvas>
  );
};

import React from 'react';
import * as THREE from 'three';

export const HumanScale: React.FC<{ position: [number, number, number] }> = ({ position }) => {
  return (
    <group position={position}>
      {/* Simple abstract human silhouette */}
      {/* Body */}
      <mesh position={[0, 0.85, 0]} castShadow>
        <boxGeometry args={[0.4, 1.3, 0.2]} />
        <meshStandardMaterial color="#d1d5db" opacity={0.6} transparent />
      </mesh>
      {/* Head */}
      <mesh position={[0, 1.65, 0]} castShadow>
        <sphereGeometry args={[0.12, 16, 16]} />
        <meshStandardMaterial color="#d1d5db" opacity={0.6} transparent />
      </mesh>
      {/* Base for stability vision */}
      <mesh position={[0, 0, 0]} receiveShadow>
        <cylinderGeometry args={[0.25, 0.25, 0.01, 32]} />
        <meshStandardMaterial color="#e5e7eb" />
      </mesh>
    </group>
  );
};

import React from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';
import { ConfigState, LayoutType, LampType, PlacedLamp } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  onTrackHover: (index: number, point: THREE.Vector3) => void;
  onTrackClick: (e: ThreeEvent<MouseEvent>, index: number) => void;
  hoveredInfo: { index: number; pos: number } | null;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, 
  onTrackHover, 
  onTrackClick,
  hoveredInfo,
  activeLampType,
  onRemoveLamp
}) => {
  const { layout, width, depth, ceilingHeight, suspensionHeight, lamps } = config;
  const trackY = ceilingHeight - suspensionHeight;
  const railThickness = 0.04;

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    return (
      <group position={pos} rotation={rot}>
        {/* Rail Geometry */}
        <mesh 
          onPointerMove={(e) => {
            e.stopPropagation();
            onTrackHover(index, e.point);
          }}
          onClick={(e) => onTrackClick(e, index)}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial color="#1a1a1a" roughness={0.8} metalness={0.2} />
        </mesh>

        {/* Suspension Cables */}
        <mesh position={[length / 2 - 0.1, suspensionHeight / 2, 0]}>
          <cylinderGeometry args={[0.005, 0.005, suspensionHeight]} />
          <meshStandardMaterial color="#4b5563" />
        </mesh>
        <mesh position={[-length / 2 + 0.1, suspensionHeight / 2, 0]}>
          <cylinderGeometry args={[0.005, 0.005, suspensionHeight]} />
          <meshStandardMaterial color="#4b5563" />
        </mesh>

        {/* Internal Slot Visualization */}
        <mesh position={[0, -railThickness/2 + 0.005, 0]}>
            <boxGeometry args={[length, 0.01, railThickness * 0.6]} />
            <meshStandardMaterial color="#000000" />
        </mesh>

        {/* Ghost Preview */}
        {activeLampType && hoveredInfo?.index === index && (
            <group position={[hoveredInfo.pos * length - length/2, -railThickness/2, 0]}>
                <LampModel type={activeLampType} isPreview />
            </group>
        )}

        {/* Placed Lamps for this segment */}
        {lamps.filter(l => l.trackIndex === index).map(lamp => (
            <group 
                key={lamp.id} 
                position={[lamp.position * length - length/2, -railThickness/2, 0]}
                onClick={(e) => {
                    e.stopPropagation();
                    onRemoveLamp(lamp.id);
                }}
            >
                <LampModel type={lamp.type} />
            </group>
        ))}
      </group>
    );
  };

  return (
    <group position={[0, trackY, 0]}>
      {layout === LayoutType.LINEAR ? (
        renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])
      ) : (
        <>
          {/* Front */}
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {/* Back */}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {/* Left */}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {/* Right */}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}
    </group>
  );
};

import React from 'react';
import { LampType } from '../types';

interface LampModelProps {
  type: LampType;
  isPreview?: boolean;
}

export const LampModel: React.FC<LampModelProps> = ({ type, isPreview }) => {
  const opacity = isPreview ? 0.4 : 1;
  const color = isPreview ? "#4ade80" : "#111111"; // Green tint for placement preview

  if (type === LampType.SPOT_DIRECTIONAL) {
    return (
      <group>
        {/* Magnetic Adapter */}
        <mesh position={[0, 0.01, 0]}>
          <boxGeometry args={[0.08, 0.02, 0.02]} />
          <meshStandardMaterial color={color} transparent opacity={opacity} />
        </mesh>
        {/* Arm */}
        <mesh position={[0, -0.05, 0]}>
          <cylinderGeometry args={[0.01, 0.01, 0.1]} />
          <meshStandardMaterial color={color} transparent opacity={opacity} />
        </mesh>
        {/* Head */}
        <group position={[0, -0.1, 0]} rotation={[0.5, 0, 0]}>
          <mesh position={[0, -0.05, 0]}>
            <cylinderGeometry args={[0.03, 0.03, 0.12]} />
            <meshStandardMaterial color={color} transparent opacity={opacity} />
          </mesh>
          {/* Lens */}
          {!isPreview && (
            <mesh position={[0, -0.11, 0]}>
                <circleGeometry args={[0.025, 32]} rotation={[-Math.PI/2, 0, 0]} />
                <meshStandardMaterial color="#fff" emissive="#fff" emissiveIntensity={2} />
            </mesh>
          )}
        </group>
      </group>
    );
  }

  // FIXED RACK (8 lights)
  return (
    <group>
      {/* Main Body */}
      <mesh position={[0, -0.015, 0]}>
        <boxGeometry args={[0.4, 0.03, 0.03]} />
        <meshStandardMaterial color={color} transparent opacity={opacity} />
      </mesh>
      {/* 8 Spots */}
      {Array.from({ length: 8 }).map((_, i) => (
        <group key={i} position={[(i - 3.5) * 0.045, -0.035, 0]}>
          <mesh>
            <boxGeometry args={[0.035, 0.01, 0.03]} />
            <meshStandardMaterial color={color} transparent opacity={opacity} />
          </mesh>
          {!isPreview && (
            <mesh position={[0, -0.006, 0]}>
              <boxGeometry args={[0.02, 0.005, 0.02]} />
              <meshStandardMaterial color="#fff" emissive="#fff" emissiveIntensity={1} />
            </mesh>
          )}
        </group>
      ))}
    </group>
  );
};

import React from 'react';
import { ConfigState, LayoutType, LampType, PRICING } from '../types';

interface SidebarProps {
  config: ConfigState;
  setConfig: React.Dispatch<React.SetStateAction<ConfigState>>;
  totalPrice: number;
  activeLampType: LampType | null;
  setActiveLampType: (type: LampType | null) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  config, 
  setConfig, 
  totalPrice,
  activeLampType,
  setActiveLampType
}) => {
  const updateConfig = (key: keyof ConfigState, value: any) => {
    setConfig(prev => ({ ...prev, [key]: value }));
  };

  const handleLayoutChange = (layout: LayoutType) => {
    // Reset lamps when layout changes drastically if needed, or just switch
    updateConfig('layout', layout);
  };

  return (
    <div className="w-[380px] bg-white border-l border-gray-100 flex flex-col h-full z-10 shadow-xl overflow-y-auto">
      {/* Header */}
      <div className="p-8 border-b border-gray-50">
        <h1 className="text-[11px] font-bold uppercase tracking-[0.2em] text-gray-400 mb-1">Lumina System</h1>
        <h2 className="text-2xl font-light text-gray-900 leading-tight">Modular Magnetic Track</h2>
      </div>

      <div className="p-8 space-y-10 flex-1">
        {/* Layout Selection */}
        <section>
          <h3 className="text-[10px] font-semibold uppercase tracking-widest text-gray-400 mb-4">Configuration</h3>
          <div className="flex gap-2">
            {[LayoutType.LINEAR, LayoutType.RECTANGULAR].map(type => (
              <button
                key={type}
                onClick={() => handleLayoutChange(type)}
                className={`flex-1 py-3 px-4 text-[10px] uppercase tracking-wider font-medium border rounded transition-all ${
                  config.layout === type 
                    ? 'bg-black text-white border-black' 
                    : 'bg-white text-gray-500 border-gray-200 hover:border-black'
                }`}
              >
                {type.toLowerCase()}
              </button>
            ))}
          </div>
        </section>

        {/* Dimensions */}
        <section className="space-y-6">
          <h3 className="text-[10px] font-semibold uppercase tracking-widest text-gray-400 mb-4">Dimensions (Meters)</h3>

          <div className="space-y-2">
            <div className="flex justify-between text-[11px] font-medium uppercase text-gray-500">
              <span>Width</span>
              <span>{config.width}m</span>
            </div>
            <input 
              type="range" min="1" max="10" step="0.5" 
              value={config.width}
              onChange={(e) => updateConfig('width', parseFloat(e.target.value))}
              className="w-full accent-black h-1 rounded-lg cursor-pointer bg-gray-100"
            />
          </div>

          {config.layout === LayoutType.RECTANGULAR && (
            <div className="space-y-2">
              <div className="flex justify-between text-[11px] font-medium uppercase text-gray-500">
                <span>Depth</span>
                <span>{config.depth}m</span>
              </div>
              <input 
                type="range" min="1" max="10" step="0.5" 
                value={config.depth}
                onChange={(e) => updateConfig('depth', parseFloat(e.target.value))}
                className="w-full accent-black h-1 rounded-lg cursor-pointer bg-gray-100"
              />
            </div>
          )}

          <div className="space-y-2">
            <div className="flex justify-between text-[11px] font-medium uppercase text-gray-500">
              <span>Ceiling Height</span>
              <span>{config.ceilingHeight}m</span>
            </div>
            <input 
              type="range" min="2.4" max="6" step="0.1" 
              value={config.ceilingHeight}
              onChange={(e) => updateConfig('ceilingHeight', parseFloat(e.target.value))}
              className="w-full accent-black h-1 rounded-lg cursor-pointer bg-gray-100"
            />
          </div>

          <div className="space-y-2">
            <div className="flex justify-between text-[11px] font-medium uppercase text-gray-500">
              <span>Suspension Distance</span>
              <span>{config.suspensionHeight}m</span>
            </div>
            <input 
              type="range" min="0.1" max="3" step="0.1" 
              value={config.suspensionHeight}
              onChange={(e) => updateConfig('suspensionHeight', parseFloat(e.target.value))}
              className="w-full accent-black h-1 rounded-lg cursor-pointer bg-gray-100"
            />
          </div>
        </section>

        {/* Catalog / Add Lamps */}
        <section>
          <h3 className="text-[10px] font-semibold uppercase tracking-widest text-gray-400 mb-4">Components Library</h3>
          <div className="grid grid-cols-1 gap-4">
            <button 
              onClick={() => setActiveLampType(LampType.SPOT_DIRECTIONAL)}
              className={`flex items-center gap-4 p-4 border rounded-lg transition-all text-left ${
                activeLampType === LampType.SPOT_DIRECTIONAL ? 'border-green-500 bg-green-50' : 'border-gray-100 hover:bg-gray-50'
              }`}
            >
              <div className="w-12 h-12 bg-black rounded flex items-center justify-center shrink-0">
                <div className="w-6 h-6 border-2 border-white rounded-full opacity-50"></div>
              </div>
              <div className="flex-1">
                <div className="text-[10px] font-bold text-gray-900 leading-tight">Track Light Bullet</div>
                <div className="text-[9px] text-gray-500 mt-0.5 tracking-wider">${PRICING.SPOT_DIRECTIONAL}.00 USD</div>
              </div>
              {activeLampType === LampType.SPOT_DIRECTIONAL && (
                <div className="text-[8px] bg-green-500 text-white px-2 py-1 rounded-full uppercase font-bold tracking-tighter">Click on rail</div>
              )}
            </button>

            <button 
              onClick={() => setActiveLampType(LampType.FIXED_RACK)}
              className={`flex items-center gap-4 p-4 border rounded-lg transition-all text-left ${
                activeLampType === LampType.FIXED_RACK ? 'border-green-500 bg-green-50' : 'border-gray-100 hover:bg-gray-50'
              }`}
            >
              <div className="w-12 h-12 bg-black rounded flex flex-col items-center justify-center gap-1 shrink-0">
                <div className="flex gap-1"><div className="w-1 h-1 bg-white rounded-full"></div><div className="w-1 h-1 bg-white rounded-full"></div></div>
                <div className="flex gap-1"><div className="w-1 h-1 bg-white rounded-full"></div><div className="w-1 h-1 bg-white rounded-full"></div></div>
              </div>
              <div className="flex-1">
                <div className="text-[10px] font-bold text-gray-900 leading-tight">Linear Fixed Rack (8x)</div>
                <div className="text-[9px] text-gray-500 mt-0.5 tracking-wider">${PRICING.FIXED_RACK}.00 USD</div>
              </div>
              {activeLampType === LampType.FIXED_RACK && (
                <div className="text-[8px] bg-green-500 text-white px-2 py-1 rounded-full uppercase font-bold tracking-tighter">Click on rail</div>
              )}
            </button>
          </div>
          <p className="mt-4 text-[9px] text-gray-400 italic text-center">
            Tip: Select a component and click on the 3D track to place it. <br/> Click an existing lamp to remove it.
          </p>
        </section>
      </div>

      {/* Footer / Total Price */}
      <div className="p-8 bg-black text-white">
        <div className="flex justify-between items-baseline mb-4">
          <span className="text-[10px] font-bold uppercase tracking-[0.2em] opacity-60">Estimated Total</span>
          <span className="text-3xl font-light">${totalPrice.toLocaleString()}.00</span>
        </div>
        <button className="w-full py-4 bg-white text-black text-[11px] font-bold uppercase tracking-widest hover:bg-gray-200 transition-colors">
          Generate Quote
        </button>
      </div>
    </div>
  );
};

export enum LayoutType {
  LINEAR = 'LINEAL',
  RECTANGULAR = 'RECTANGULAR'
}

export enum MountingType {
  SUSPENDIDO = 'SUSPENDIDO',
  SUPERFICIAL = 'SUPERFICIAL',
  EMBUTIDO = 'EMBUTIDO'
}

export enum LampType {
  SPOT_DIRECTIONAL = 'SPOT_DIRECTIONAL',
  FIXED_RACK = 'FIXED_RACK'
}

export interface PlacedLamp {
  id: string;
  type: LampType;
  trackIndex: number; // 0-3 for rectangular, 0 for linear
  position: number;   // 0 to 1 along the track segment
}

export interface ConfigState {
  layout: LayoutType;
  mounting: MountingType;
  width: number;
  depth: number;
  ceilingHeight: number;
  suspensionHeight: number;
  lamps: PlacedLamp[];
  includeInstallation: boolean;
  includeShipping: boolean;
}

export const PRICING = {
  RAIL_KIT_2M: 70,
  SPOT_DIRECTIONAL: 33,
  FIXED_RACK: 60,
  INSTALLATION_BASE: 50,
  INSTALLATION_PER_ITEM: 5,
  SHIPPING: 25
};

import React, { useState, useMemo, useCallback } from 'react';
import { Scene3D } from './components/Scene3D';
import { Sidebar } from './components/Sidebar';
import { ConfigState, LayoutType, MountingType, PlacedLamp, PRICING, LampType } from './types';

const App: React.FC = () => {
  const [config, setConfig] = useState<ConfigState>({
    layout: LayoutType.LINEAR,
    mounting: MountingType.SUSPENDIDO,
    width: 3,
    depth: 2,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    lamps: [],
    includeInstallation: false,
    includeShipping: false
  });

  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);

  const quoteData = useMemo(() => {
    let railSegments = 0;
    if (config.layout === LayoutType.LINEAR) {
      railSegments = Math.ceil(config.width / 2);
    } else {
      railSegments = Math.ceil((config.width * 2 + config.depth * 2) / 2);
    }

    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const spotCount = config.lamps.filter(l => l.type === LampType.SPOT_DIRECTIONAL).length;
    const rackCount = config.lamps.filter(l => l.type === LampType.FIXED_RACK).length;

    const spotsCost = spotCount * PRICING.SPOT_DIRECTIONAL;
    const racksCost = rackCount * PRICING.FIXED_RACK;

    let installationCost = 0;
    if (config.includeInstallation) {
      installationCost = PRICING.INSTALLATION_BASE + (config.lamps.length * PRICING.INSTALLATION_PER_ITEM);
    }

    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments,
      railCost,
      spotCount,
      spotsCost,
      rackCount,
      racksCost,
      installationCost,
      shippingCost,
      total: railCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const addLamp = useCallback((type: LampType, trackIndex: number, position: number) => {
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      trackIndex,
      position
    };
    setConfig(prev => ({
      ...prev,
      lamps: [...prev.lamps, newLamp]
    }));
  }, []);

  const removeLamp = useCallback((id: string) => {
    setConfig(prev => ({
