import React from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';
import { ConfigState, LayoutType, LampType, PlacedLamp, MountingType } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  onTrackHover: (index: number, point: THREE.Vector3) => void;
  onTrackClick: (e: ThreeEvent<MouseEvent>, index: number) => void;
  hoveredInfo: { index: number; pos: number } | null;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, 
  onTrackHover, 
  onTrackClick,
  hoveredInfo,
  activeLampType,
  onRemoveLamp
}) => {
  const { layout, mounting, width, depth, ceilingHeight, suspensionHeight, lamps } = config;

  // Calculate vertical position of the rail
  let trackY = 0;
  let finalSuspensionHeight = 0;

  if (mounting === MountingType.SUSPENDIDO) {
    trackY = ceilingHeight - suspensionHeight;
    finalSuspensionHeight = suspensionHeight;
  } else if (mounting === MountingType.SUPERFICIAL) {
    trackY = ceilingHeight - 0.02; // Just below ceiling surface
    finalSuspensionHeight = 0;
  } else if (mounting === MountingType.EMBUTIDO) {
    trackY = ceilingHeight + 0.015; // Partially inside ceiling
    finalSuspensionHeight = 0;
  }

  const railThickness = 0.04;

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    return (
      <group position={pos} rotation={rot}>
        {/* Rail Geometry */}
        <mesh 
          onPointerMove={(e) => {
            e.stopPropagation();
            onTrackHover(index, e.point);
          }}
          onClick={(e) => onTrackClick(e, index)}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial 
            color="#1a1a1a" 
            roughness={0.8} 
            metalness={0.2} 
            // If embutido, slightly shift or handle depth so it looks recessed
          />
        </mesh>

        {/* Suspension Cables (Only for SUSPENDIDO) */}
        {mounting === MountingType.SUSPENDIDO && (
          <>
            <mesh position={[length / 2 - 0.1, finalSuspensionHeight / 2, 0]}>
              <cylinderGeometry args={[0.005, 0.005, finalSuspensionHeight]} />
              <meshStandardMaterial color="#4b5563" />
            </mesh>
            <mesh position={[-length / 2 + 0.1, finalSuspensionHeight / 2, 0]}>
              <cylinderGeometry args={[0.005, 0.005, finalSuspensionHeight]} />
              <meshStandardMaterial color="#4b5563" />
            </mesh>
          </>
        )}

        {/* Embutido Trim (Flange for recessed look) */}
        {mounting === MountingType.EMBUTIDO && (
          <mesh position={[0, -0.019, 0]}>
            <boxGeometry args={[length + 0.02, 0.002, railThickness + 0.02]} />
            <meshStandardMaterial color="#111111" />
          </mesh>
        )}

        {/* Ghost Preview */}
        {activeLampType && hoveredInfo?.index === index && (
            <group position={[hoveredInfo.pos * length - length/2, -railThickness/2, 0]}>
                <LampModel type={activeLampType} isPreview />
            </group>
        )}

        {/* Placed Lamps */}
        {lamps.filter(l => l.trackIndex === index).map(lamp => (
            <group 
                key={lamp.id} 
                position={[lamp.position * length - length/2, -railThickness/2, 0]}
                onClick={(e) => {
                    e.stopPropagation();
                    onRemoveLamp(lamp.id);
                }}
            >
                <LampModel type={lamp.type} />
            </group>
        ))}
      </group>
    );
  };

  return (
    <group position={[0, trackY, 0]}>
      {layout === LayoutType.LINEAR ? (
        renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])
      ) : (
        <>
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}
    </group>
  );
};

