  RAIL_KIT_2M: 70,
  SPOT_DIRECTIONAL: 33,
  FIXED_RACK: 60,
  CORNER_PIECE: 25,
  INSTALLATION_BASE: 50,
  INSTALLATION_PER_ITEM: 5,
  SHIPPING: 25
};

