import React, { Suspense, useRef, useState } from 'react';
import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment, Grid, ContactShadows } from '@react-three/drei';
import * as THREE from 'three';
import { ConfigState, LampType, LayoutType, PlacedLamp, MountingType } from '../types';
import { HumanScale } from './HumanScale';
import { TrackSystem } from './TrackSystem';

interface Scene3DProps {
  config: ConfigState;
  activeLampType: LampType | null;
  onPlaceLamp: (type: LampType, trackIndex: number, position: number) => void;
  onRemoveLamp: (id: string) => void;
  onCancelPlacement: () => void;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  sceneGroupRef: React.RefObject<THREE.Group>;
}

export const Scene3D: React.FC<Scene3DProps> = ({ 
  config, 
  activeLampType, 
  onPlaceLamp, 
  onRemoveLamp,
  onCancelPlacement,
  canvasRef,
  sceneGroupRef
}) => {
  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);

  const handleTrackHover = (index: number, point: THREE.Vector3) => {
    if (!activeLampType) return;

    let pos = 0;
    // We need logic to determine the hit position based on segment length
    // For simplicity, we use the local position of the segment later in TrackSystem
    // Here we just pass raw info to the handler
    setHoveredTrack({ index, pos: 0.5 }); // TrackSystem will refine this
  };

  const handleTrackClick = (e: ThreeEvent<MouseEvent>, index: number, refinedPos: number) => {
    if (activeLampType) {
      onPlaceLamp(activeLampType, index, refinedPos);
      onCancelPlacement();
    }
    e.stopPropagation();
  };

  return (
    <Canvas 
      shadows 
      className="w-full h-full" 
      ref={canvasRef}
      gl={{ preserveDrawingBuffer: true, antialias: true }}
    >
      <PerspectiveCamera makeDefault position={[5, 4, 8]} fov={45} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 2.1} 
        enableDamping 
        makeDefault
      />

      <ambientLight intensity={0.6} />
      <spotLight position={[10, 15, 10]} angle={0.2} penumbra={1} intensity={1.5} castShadow />

      <Suspense fallback={null}>
        <Environment preset="city" />

        {/* Ceiling Mesh */}
        <mesh 
          position={[0, config.ceilingHeight, 0]} 
          rotation={[Math.PI / 2, 0, 0]} 
          receiveShadow
        >
          <planeGeometry args={[30, 30]} />
          <meshStandardMaterial color="#ffffff" side={THREE.DoubleSide} roughness={0.9} />
        </mesh>

        {/* Floor - Cleaned: Only Grid & Shadows */}
        <Grid 
          infiniteGrid 
          fadeDistance={40} 
          fadeStrength={6} 
          sectionSize={1} 
          sectionColor="#cfd8dc" 
          cellSize={0.25} 
          cellColor="#eceff1"
          position={[0, 0.001, 0]}
        />

        <HumanScale position={[2, 0, 1.5]} />

        {/* Track System with Export Ref */}
        <group ref={sceneGroupRef}>
          <TrackSystem 
            config={config} 
            onTrackHover={(index, point) => setHoveredTrack({ index, pos: 0.5 /* refined inside */ })}
            onTrackClick={handleTrackClick}
            activeLampType={activeLampType}
            onRemoveLamp={onRemoveLamp}
          />
        </group>

        <ContactShadows 
          position={[0, 0, 0]} 
          opacity={0.25} 
          scale={25} 
          blur={2.5} 
          far={6} 
        />
      </Suspense>
    </Canvas>
  );
};

import React, { useState } from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';
import { ConfigState, LayoutType, LampType, PlacedLamp, MountingType } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  onTrackHover: (index: number, point: THREE.Vector3) => void;
  onTrackClick: (e: ThreeEvent<MouseEvent>, index: number, pos: number) => void;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, 
  onTrackHover, 
  onTrackClick,
  activeLampType,
  onRemoveLamp
}) => {
  const { layout, mounting, width, depth, ceilingHeight, suspensionHeight, lamps } = config;
  const [hoveredPos, setHoveredPos] = useState<{ index: number; pos: number } | null>(null);

  let trackY = 0;
  let finalSuspensionHeight = 0;

  if (mounting === MountingType.SUSPENDIDO) {
    trackY = ceilingHeight - suspensionHeight;
    finalSuspensionHeight = suspensionHeight;
  } else if (mounting === MountingType.SUPERFICIAL) {
    trackY = ceilingHeight - 0.02;
    finalSuspensionHeight = 0;
  } else if (mounting === MountingType.EMBUTIDO) {
    trackY = ceilingHeight + 0.015;
    finalSuspensionHeight = 0;
  }

  const railThickness = 0.04;

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    return (
      <group position={pos} rotation={rot}>
        {/* Rail Geometry */}
        <mesh 
          onPointerMove={(e) => {
            e.stopPropagation();
            // Calculate normalized local position
            const localPoint = e.point.clone().applyMatrix4(new THREE.Matrix4().copy(e.object.matrixWorld).invert());
            const normalizedPos = (localPoint.x + length / 2) / length;
            setHoveredPos({ index, pos: Math.max(0, Math.min(1, normalizedPos)) });
            onTrackHover(index, e.point);
          }}
          onPointerOut={() => setHoveredPos(null)}
          onClick={(e) => {
            if (hoveredPos) onTrackClick(e, index, hoveredPos.pos);
          }}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial color="#1a1a1a" roughness={0.8} metalness={0.2} />
        </mesh>

        {/* Suspension Cables */}
        {mounting === MountingType.SUSPENDIDO && (
          <>
            <mesh position={[length / 2 - 0.05, finalSuspensionHeight / 2, 0]}>
              <cylinderGeometry args={[0.004, 0.004, finalSuspensionHeight]} />
              <meshStandardMaterial color="#546e7a" />
            </mesh>
            <mesh position={[-length / 2 + 0.05, finalSuspensionHeight / 2, 0]}>
              <cylinderGeometry args={[0.004, 0.004, finalSuspensionHeight]} />
              <meshStandardMaterial color="#546e7a" />
            </mesh>
          </>
        )}

        {mounting === MountingType.EMBUTIDO && (
          <mesh position={[0, -0.019, 0]}>
            <boxGeometry args={[length + 0.02, 0.002, railThickness + 0.02]} />
            <meshStandardMaterial color="#111111" />
          </mesh>
        )}

        {/* Preview */}
        {activeLampType && hoveredPos?.index === index && (
          <group position={[hoveredPos.pos * length - length/2, -railThickness/2, 0]}>
            <LampModel type={activeLampType} isPreview />
          </group>
        )}

        {/* Lamps */}
        {lamps.filter(l => l.trackIndex === index).map(lamp => (
          <group 
            key={lamp.id} 
            position={[lamp.position * length - length/2, -railThickness/2, 0]}
            onClick={(e) => {
              e.stopPropagation();
              onRemoveLamp(lamp.id);
            }}
          >
            <LampModel type={lamp.type} />
          </group>
        ))}
      </group>
    );
  };

  return (
    <group position={[0, trackY, 0]}>
      {layout === LayoutType.LINEAR && renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])}

      {layout === LayoutType.RECTANGULAR && (
        <>
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}

      {layout === LayoutType.L_SHAPE && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
        </>
      )}

      {layout === LayoutType.U_SHAPE && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
          {renderTrackSegment(2, width, [width / 2, 0, depth], [0, 0, 0])}
        </>
      )}
    </group>
  );
};

