import React, { useState, useMemo, useCallback, useRef } from 'react';
import { Scene3D } from './components/Scene3D';
import { Sidebar } from './components/Sidebar';
import { ProductModal } from './components/ProductModal';
import { ConfigState, LayoutType, MountingType, PlacedLamp, PRICING, LampType } from './types';
import * as THREE from 'three';

const App: React.FC = () => {
  const [config, setConfig] = useState<ConfigState>({
    layout: LayoutType.LINEAR,
    mounting: MountingType.SUSPENDIDO,
    width: 3,
    depth: 2,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    lamps: [],
    includeInstallation: false,
    includeShipping: false,
    showEnvironment: true
  });

  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<LampType | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  const quoteData = useMemo(() => {
    let railLength = 0;
    let cornerCount = 0;

    switch (config.layout) {
      case LayoutType.LINEAR:
        railLength = config.width;
        cornerCount = 0;
        break;
      case LayoutType.RECTANGULAR:
        railLength = (config.width * 2) + (config.depth * 2);
        cornerCount = 4;
        break;
      case LayoutType.L_SHAPE:
        railLength = config.width + config.depth;
        cornerCount = 1;
        break;
      case LayoutType.U_SHAPE:
        railLength = (config.width * 2) + config.depth;
        cornerCount = 2;
        break;
    }

    const railSegments = Math.ceil(railLength / 2);
    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const cornersCost = cornerCount * PRICING.CORNER_PIECE;

    const spotCount = config.lamps.filter(l => l.type === LampType.SPOT_DIRECTIONAL).length;
    const rackCount = config.lamps.filter(l => l.type === LampType.FIXED_RACK).length;

    const spotsCost = spotCount * PRICING.SPOT_DIRECTIONAL;
    const racksCost = rackCount * PRICING.FIXED_RACK;

    let installationCost = 0;
    if (config.includeInstallation) {
      installationCost = PRICING.INSTALLATION_BASE + (config.lamps.length * PRICING.INSTALLATION_PER_ITEM);
    }

    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments,
      railCost,
      cornerCount,
      cornersCost,
      spotCount,
      spotsCost,
      rackCount,
      racksCost,
      installationCost,
      shippingCost,
      total: railCost + cornersCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const addLamp = useCallback((type: LampType, trackIndex: number, position: number) => {
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      trackIndex,
      position
    };
    setConfig(prev => ({
      ...prev,
      lamps: [...prev.lamps, newLamp]
    }));
  }, []);

  const removeLamp = useCallback((id: string) => {
    setConfig(prev => ({
      ...prev,
      lamps: prev.lamps.filter(l => l.id !== id)
    }));
  }, []);

  const handleExport3D = async () => {
    if (!sceneGroupRef.current) return;

    // Importamos ColladaExporter ya que es un formato nativo de importación en SketchUp (.dae)
    const { ColladaExporter } = await import('three/examples/jsm/exporters/ColladaExporter.js');
    const exporter = new ColladaExporter();

    // El exportador de Collada devuelve un objeto con la propiedad .data que es el XML string
    const result = exporter.parse(sceneGroupRef.current, (res) => {
        const blob = new Blob([res.data], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = `lumina_system_${config.layout.toLowerCase().replace(' ', '_')}.dae`;
        link.click();
    }, { version: '1.4.1', author: 'EOS Iluminación' });
  };

  const handleDownloadPDF = () => {
    const canvas = canvasRef.current;
    const imgData = canvas ? canvas.toDataURL('image/png') : '';

    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const html = `
      <html>
        <head>
          <title>Cotización Lumina System</title>
          <style>
            @page { size: letter; margin: 20mm; }
            body { font-family: 'Inter', sans-serif; padding: 20px; color: #1a1a1a; line-height: 1.4; max-width: 800px; margin: auto; }
            .header { display: flex; justify-content: space-between; border-bottom: 3px solid #000; padding-bottom: 20px; margin-bottom: 30px; }
            .header h1 { margin: 0; font-size: 28px; font-weight: 300; text-transform: uppercase; letter-spacing: 4px; }
            .snapshot { width: 100%; height: 300px; background: #f9f9f9; display: flex; align-items: center; justify-content: center; margin-bottom: 30px; border-radius: 8px; overflow: hidden; border: 1px solid #eee; }
            .snapshot img { max-width: 100%; max-height: 100%; object-fit: contain; }
            .section { margin-bottom: 25px; }
            .section-title { font-weight: 700; text-transform: uppercase; font-size: 11px; color: #888; margin-bottom: 12px; border-bottom: 1px solid #eee; padding-bottom: 4px; }
            table { width: 100%; border-collapse: collapse; margin-top: 10px; }
            th { text-align: left; font-size: 11px; text-transform: uppercase; color: #aaa; padding: 12px 8px; border-bottom: 1px solid #eee; }
            td { padding: 12px 8px; border-bottom: 1px solid #f5f5f5; font-size: 13px; }
            .total-box { background: #000; color: #fff; padding: 20px; display: flex; justify-content: space-between; align-items: center; margin-top: 20px; border-radius: 4px; }
            .footer { margin-top: 40px; font-size: 9px; color: #aaa; text-align: center; border-top: 1px solid #eee; padding-top: 20px; }
          </style>
        </head>
        <body>
          <div class="header">
            <div>
              <h1>Lumina</h1>
              <p style="font-size: 10px; color: #888; margin-top: 5px;">SISTEMA DE ILUMINACIÓN MAGNÉTICA 48V</p>
            </div>
            <div style="text-align: right">
              <p style="font-size: 12px; font-weight: bold;">COTIZACIÓN #LS-${Math.floor(Math.random() * 9000) + 1000}</p>
              <p style="font-size: 10px; color: #888;">${new Date().toLocaleDateString('es-ES')}</p>
            </div>
          </div>

          <div class="snapshot">
            ${imgData ? `<img src="${imgData}" />` : '<p>Visualización 3D no disponible</p>'}
          </div>

          <div class="section">
            <div class="section-title">Especificaciones de Diseño</div>
            <p style="font-size: 12px;">Configuración: <strong>${config.layout}</strong> | Montaje: <strong>${config.mounting}</strong> | Dimensiones: <strong>${config.width}m x ${config.depth}m</strong></p>
          </div>

          <div class="section">
            <div class="section-title">Detalle de Componentes</div>
            <table>
              <thead>
                <tr>
                  <th>Descripción</th>
                  <th style="text-align:center">Cant.</th>
                  <th style="text-align:right">Unit.</th>
                  <th style="text-align:right">Subtotal</th>
                </tr>
              </thead>
              <tbody>
                <tr>
                  <td>Tramo Riel Negro 48v Magnético (2000mm)</td>
                  <td style="text-align:center">${quoteData.railSegments}</td>
                  <td style="text-align:right">$${PRICING.RAIL_KIT_2M}.00</td>
                  <td style="text-align:right">$${quoteData.railCost}.00</td>
                </tr>
                ${quoteData.cornerCount > 0 ? `
                <tr>
                  <td>Conector de Esquina L 90° Magnético</td>
                  <td style="text-align:center">${quoteData.cornerCount}</td>
                  <td style="text-align:right">$${PRICING.CORNER_PIECE}.00</td>
                  <td style="text-align:right">$${quoteData.cornersCost}.00</td>
                </tr>` : ''}
                ${quoteData.spotCount > 0 ? `
                <tr>
                  <td>Spot Bala Magnético 12W 4000K</td>
                  <td style="text-align:center">${quoteData.spotCount}</td>
                  <td style="text-align:right">$${PRICING.SPOT_DIRECTIONAL}.00</td>
                  <td style="text-align:right">$${quoteData.spotsCost}.00</td>
                </tr>` : ''}
                ${quoteData.rackCount > 0 ? `
                <tr>
                  <td>Rack Lineal Fijo (8 Luces) Difuso</td>
                  <td style="text-align:center">${quoteData.rackCount}</td>
                  <td style="text-align:right">$${PRICING.FIXED_RACK}.00</td>
                  <td style="text-align:right">$${quoteData.racksCost}.00</td>
                </tr>` : ''}
              </tbody>
            </table>
          </div>

          <div class="section">
            <div class="section-title">Logística y Servicios</div>
            <table>
              <tbody>
                ${config.includeInstallation ? `
                <tr>
                  <td>Montaje y Calibración Profesional</td>
                  <td style="text-align:right">$${quoteData.installationCost}.00</td>
                </tr>` : ''}
                ${config.includeShipping ? `
                <tr>
                  <td>Seguro de Transporte y Entrega</td>
                  <td style="text-align:right">$${quoteData.shippingCost}.00</td>
                </tr>` : ''}
              </tbody>
            </table>
          </div>

          <div class="total-box">
            <span style="font-size: 12px; text-transform: uppercase; letter-spacing: 2px;">Inversión Total Estimada</span>
            <span style="font-size: 24px; font-weight: bold;">$${quoteData.total.toLocaleString()}.00 USD</span>
          </div>

          <div class="footer">
            Precios sujetos a disponibilidad de stock. Esta cotización tiene una validez de 10 días hábiles.
            Lumina System S.A. | Innovación en Iluminación Técnica.
          </div>
          <script>setTimeout(() => { window.print(); window.close(); }, 500);</script>
        </body>
      </html>
    `;
    printWindow.document.write(html);
    printWindow.document.close();
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden">
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          onCancelPlacement={() => setActiveLampType(null)}
          canvasRef={canvasRef}
          sceneGroupRef={sceneGroupRef}
        />
        <div className="absolute bottom-6 left-6 text-[10px] uppercase tracking-widest text-gray-400 pointer-events-none">
          Vista 1:1 | {config.layout} | {config.mounting} | {config.width.toFixed(1)}m x {config.depth.toFixed(1)}m
        </div>
      </div>

      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        quoteData={quoteData}
        activeLampType={activeLampType}
        setActiveLampType={setActiveLampType}
        onDownloadPDF={handleDownloadPDF}
        onExport3D={handleExport3D}
        onProductDetail={(type) => setSelectedProduct(type)}
      />

      <ProductModal 
        productType={selectedProduct} 
        onClose={() => setSelectedProduct(null)} 
      />
    </div>
  );
};

export default App;

