  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);

  const handleTrackHover = (index: number, point: THREE.Vector3) => {
    if (!activeLampType) return;
    setHoveredTrack({ index, pos: 0.5 });
  };

  const handleTrackClick = (e: ThreeEvent<MouseEvent>, index: number, refinedPos: number) => {
    if (activeLampType) {
      onPlaceLamp(activeLampType, index, refinedPos);
      onCancelPlacement();
    }
    e.stopPropagation();
  };

  return (
    <Canvas 
      shadows 
      className="w-full h-full" 
      ref={canvasRef}
      gl={{ preserveDrawingBuffer: true, antialias: true }}
    >
      <PerspectiveCamera makeDefault position={[7, 5, 10]} fov={40} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 2.1} 
        enableDamping 
        makeDefault
      />

      <ambientLight intensity={0.5} />
      <spotLight position={[10, 15, 10]} angle={0.25} penumbra={1} intensity={1.8} castShadow />
      <directionalLight position={[-5, 10, -5]} intensity={0.4} />

      <Suspense fallback={null}>
        <Environment preset="apartment" />

        {/* Techo */}
        <mesh 
          position={[0, config.ceilingHeight, 0]} 
          rotation={[Math.PI / 2, 0, 0]} 
          receiveShadow
        >
          <planeGeometry args={[50, 50]} />
          <meshStandardMaterial color="#ffffff" side={THREE.DoubleSide} roughness={1} />
        </mesh>

        {/* Cuadrícula Limpia - Solo líneas, sin fondo sólido para evitar titileo */}
        <Grid 
          infiniteGrid 
          fadeDistance={50} 
          fadeStrength={10} 
          sectionSize={2} 
          sectionColor="#d1d5db" 
          sectionThickness={1.5}
          cellSize={0.5} 
          cellColor="#e5e7eb"
          cellThickness={1}
          position={[0, -0.001, 0]} // Ligeramente debajo de 0 para evitar conflictos con sombras de contacto
        />

        {/* Contexto de Mobiliario */}
        {config.showEnvironment && <EnvironmentContext />}

        {/* Sistema de Rieles */}
        <group ref={sceneGroupRef}>
          <TrackSystem 
            config={config} 
            onTrackHover={(index, point) => setHoveredTrack({ index, pos: 0.5 })}
            onTrackClick={handleTrackClick}
            activeLampType={activeLampType}
            onRemoveLamp={onRemoveLamp}
          />
        </group>

        <ContactShadows 
          position={[0, 0, 0]} 
          opacity={0.25} 
          scale={40} 
          blur={2.5} 
          far={8} 
        />
      </Suspense>
    </Canvas>
  );
};

