import React, { useState, useMemo, useCallback, useRef } from 'react';
import { Scene3D } from './components/Scene3D';
import { Sidebar } from './components/Sidebar';
import { ProductModal } from './components/ProductModal';
import { ConfigState, LayoutType, MountingType, PlacedLamp, PRICING, LampType, EnvironmentType } from './types';
import * as THREE from 'three';

const App: React.FC = () => {
  const [config, setConfig] = useState<ConfigState>({
    layout: LayoutType.LINEAR,
    mounting: MountingType.SUSPENDIDO,
    environmentType: EnvironmentType.HOME,
    width: 3,
    depth: 2,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    lamps: [],
    includeInstallation: false,
    includeShipping: false,
    showEnvironment: true
  });

  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<LampType | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  const quoteData = useMemo(() => {
    let railLength = 0;
    let cornerCount = 0;

    switch (config.layout) {
      case LayoutType.LINEAR: railLength = config.width; cornerCount = 0; break;
      case LayoutType.RECTANGULAR: railLength = (config.width * 2) + (config.depth * 2); cornerCount = 4; break;
      case LayoutType.L_SHAPE: railLength = config.width + config.depth; cornerCount = 1; break;
      case LayoutType.U_SHAPE: railLength = (config.width * 2) + config.depth; cornerCount = 2; break;
    }

    const railSegments = Math.ceil(railLength / 2);
    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const cornersCost = cornerCount * PRICING.CORNER_PIECE;
    const spotCount = config.lamps.filter(l => l.type === LampType.SPOT_DIRECTIONAL).length;
    const rackCount = config.lamps.filter(l => l.type === LampType.FIXED_RACK).length;
    const spotsCost = spotCount * PRICING.SPOT_DIRECTIONAL;
    const racksCost = rackCount * PRICING.FIXED_RACK;

    const installationCost = config.includeInstallation 
      ? PRICING.INSTALLATION_BASE + (config.lamps.length * PRICING.INSTALLATION_PER_ITEM) 
      : 0;
    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments, railCost, cornerCount, cornersCost, spotCount, spotsCost, rackCount, racksCost,
      installationCost, shippingCost, total: railCost + cornersCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const addLamp = useCallback((type: LampType, trackIndex: number, position: number) => {
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      trackIndex,
      position,
      rotation: type === LampType.SPOT_DIRECTIONAL ? (Math.random() - 0.5) * 2 * Math.PI : 0
    };
    setConfig(prev => ({ ...prev, lamps: [...prev.lamps, newLamp] }));
  }, []);

  const removeLamp = useCallback((id: string) => {
    setConfig(prev => ({ ...prev, lamps: prev.lamps.filter(l => l.id !== id) }));
  }, []);

  const handleExport3D = async () => {
    if (!sceneGroupRef.current) return;
    const { ColladaExporter } = await import('three/examples/jsm/exporters/ColladaExporter.js');
    const exporter = new ColladaExporter();
    exporter.parse(sceneGroupRef.current, (result) => {
      const blob = new Blob([result.data], { type: 'text/xml' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `lumina_system_${config.layout.toLowerCase()}.dae`;
      link.click();
    }, { version: '1.4.1' });
  };

  const handleDownloadPDF = () => {
    const canvas = canvasRef.current;
    const imgData = canvas ? canvas.toDataURL('image/png') : '';
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const html = `
      <html><head><title>Cotización Lumina</title>
      <style>
        body { font-family: 'Inter', sans-serif; padding: 40px; color: #1a1a1a; max-width: 800px; margin: auto; }
        .header { display: flex; justify-content: space-between; border-bottom: 2px solid #000; padding-bottom: 20px; }
        .snapshot { width: 100%; height: 250px; margin: 30px 0; border: 1px solid #eee; overflow: hidden; display: flex; align-items: center; justify-content: center; }
        .snapshot img { max-width: 100%; max-height: 100%; }
        table { width: 100%; border-collapse: collapse; margin-top: 20px; }
        th { text-align: left; padding: 10px; border-bottom: 1px solid #eee; font-size: 10px; text-transform: uppercase; color: #888; }
        td { padding: 10px; border-bottom: 1px solid #f5f5f5; font-size: 12px; }
        .total { background: #000; color: #fff; padding: 20px; display: flex; justify-content: space-between; margin-top: 30px; font-weight: bold; }
      </style></head>
      <body>
        <div class="header"><div><h1>Lumina</h1><p>Magnetic 48V Lighting</p></div><div style="text-align:right"><p>#${Math.floor(Math.random()*9000)+1000}</p><p>${new Date().toLocaleDateString()}</p></div></div>
        <div class="snapshot"><img src="${imgData}" /></div>
        <table><thead><tr><th>Item</th><th>Cant.</th><th>Precio</th></tr></thead><tbody>
          <tr><td>Riel Negro 2000mm</td><td>${quoteData.railSegments}</td><td>$${quoteData.railCost}</td></tr>
          ${quoteData.cornerCount > 0 ? `<tr><td>Esquinas 90°</td><td>${quoteData.cornerCount}</td><td>$${quoteData.cornersCost}</td></tr>` : ''}
          ${quoteData.spotCount > 0 ? `<tr><td>Spots Bala</td><td>${quoteData.spotCount}</td><td>$${quoteData.spotsCost}</td></tr>` : ''}
          ${quoteData.rackCount > 0 ? `<tr><td>Racks Lineales</td><td>${quoteData.rackCount}</td><td>$${quoteData.racksCost}</td></tr>` : ''}
        </tbody></table>
        <div class="total"><span>INVERSIÓN TOTAL</span><span>$${quoteData.total.toLocaleString()}.00</span></div>
      </body><script>setTimeout(() => { window.print(); window.close(); }, 500);</script></html>`;
    printWindow.document.write(html);
    printWindow.document.close();
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden">
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          canvasRef={canvasRef}
          sceneGroupRef={sceneGroupRef}
        />
        <div className="absolute bottom-6 left-6 text-[10px] uppercase tracking-widest text-gray-300 pointer-events-none">
          {config.layout} | {config.mounting} | {config.width.toFixed(1)}m x {config.depth.toFixed(1)}m
        </div>
      </div>
      <Sidebar 
        config={config} setConfig={setConfig} 
        quoteData={quoteData}
        activeLampType={activeLampType} setActiveLampType={setActiveLampType}
        onDownloadPDF={handleDownloadPDF} onExport3D={handleExport3D}
        onProductDetail={setSelectedProduct}
      />
      <ProductModal productType={selectedProduct} onClose={() => setSelectedProduct(null)} />
    </div>
  );
};

export default App;

