import React, { Suspense, useRef, useState } from 'react';
import { Canvas, useFrame, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment, Grid, ContactShadows, PivotControls } from '@react-three/drei';
import * as THREE from 'three';
import { ConfigState, LampType, LayoutType, PlacedLamp, MountingType, EnvironmentType } from '../types';
import { EnvironmentContext } from './EnvironmentContext';
import { TrackSystem } from './TrackSystem';

interface Scene3DProps {
  config: ConfigState;
  activeLampType: LampType | null;
  onPlaceLamp: (type: LampType, systemId: string, trackIndex: number, position: number) => void;
  onRemoveLamp: (systemId: string, id: string) => void;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  sceneGroupRef: React.RefObject<THREE.Group>;
  onUpdateSystemPos: (id: string, pos: [number, number, number]) => void;
  onUpdateObjectPos: (id: string, pos: [number, number, number]) => void;
  onCloneObject: (id: string) => void;
}

export const Scene3D: React.FC<Scene3DProps> = ({ 
  config, 
  activeLampType, 
  onPlaceLamp, 
  onRemoveLamp,
  canvasRef,
  sceneGroupRef,
  onUpdateSystemPos,
  onUpdateObjectPos,
  onCloneObject
}) => {
  return (
    <Canvas 
      shadows 
      className="w-full h-full bg-[#fdfdfd]" 
      ref={canvasRef}
      gl={{ preserveDrawingBuffer: true, antialias: true }}
    >
      <PerspectiveCamera makeDefault position={[8, 5, 8]} fov={35} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 2.1} 
        enableDamping 
        makeDefault
      />

      <ambientLight intensity={0.6} />
      <spotLight position={[10, 20, 10]} angle={0.25} penumbra={1} intensity={2} castShadow />

      <Suspense fallback={null}>
        <Environment preset="apartment" />

        {/* Ceiling */}
        <mesh position={[0, config.ceilingHeight, 0]} rotation={[Math.PI / 2, 0, 0]} receiveShadow>
          <planeGeometry args={[50, 50]} />
          <meshStandardMaterial color="#ffffff" side={THREE.DoubleSide} roughness={1} />
        </mesh>

        <Grid 
          infiniteGrid 
          fadeDistance={40} 
          fadeStrength={10} 
          sectionSize={2} 
          sectionColor="#cfd8dc" 
          sectionThickness={1}
          cellSize={0.5} 
          cellColor="#eceff1"
          cellThickness={0.5}
          position={[0, -0.001, 0]}
        />

        {config.showEnvironment && (
          <EnvironmentContext 
            config={config} 
            onUpdatePos={onUpdateObjectPos} 
            onClone={onCloneObject}
          />
        )}

        <group ref={sceneGroupRef}>
          {config.systems.map((sys) => (
            <group key={sys.id} position={sys.position}>
              <PivotControls 
                active={config.selectedSystemId === sys.id} 
                depthTest={false} 
                anchor={[0, 0, 0]} 
                disableRotations 
                scale={0.5}
                onDrag={(matrix) => {
                  const pos = new THREE.Vector3();
                  pos.setFromMatrixPosition(matrix);
                  onUpdateSystemPos(sys.id, [pos.x, 0, pos.z]);
                }}
              >
                <TrackSystem 
                  config={config} 
                  systemId={sys.id}
                  systemConfig={sys}
                  onTrackClick={(e, trackIdx, pos) => onPlaceLamp(activeLampType!, sys.id, trackIdx, pos)}
                  activeLampType={activeLampType}
                  onRemoveLamp={(lampId) => onRemoveLamp(sys.id, lampId)}
                />
              </PivotControls>
            </group>
          ))}
        </group>

        <ContactShadows position={[0, 0, 0]} opacity={0.2} scale={30} blur={2.5} far={8} />
      </Suspense>
    </Canvas>
  );
};

import React, { useState } from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';
import { ConfigState, LampType, TrackSystemConfig, MountingType } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  systemId: string;
  systemConfig: TrackSystemConfig;
  onTrackClick: (e: ThreeEvent<MouseEvent>, trackIndex: number, pos: number) => void;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, 
  systemId,
  systemConfig,
  onTrackClick,
  activeLampType,
  onRemoveLamp
}) => {
  const { mounting, width, depth, lamps } = systemConfig;
  const { ceilingHeight, suspensionHeight } = config;
  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);

  const trackY = mounting === MountingType.SUSPENDIDO ? ceilingHeight - suspensionHeight : (mounting === MountingType.SUPERFICIAL ? ceilingHeight - 0.02 : ceilingHeight + 0.015);
  const finalSuspensionHeight = mounting === MountingType.SUSPENDIDO ? suspensionHeight : 0;
  const railThickness = 0.04;

  const getTensorPositions = (length: number, isStart: boolean, isEnd: boolean) => {
    const edgeOffset = 0.1; 
    // If it's a corner junction, we might want to shift the tensor a bit further for visual "continuity"
    // but the 10cm rule is generally reliable.
    if (length <= 2 * edgeOffset) return [0];

    const effLength = length - 2 * edgeOffset;
    const maxSpacing = 1.6;
    const numIntervals = Math.max(1, Math.ceil(effLength / maxSpacing));
    const spacing = effLength / numIntervals;

    const positions = [];
    for (let i = 0; i <= numIntervals; i++) {
      positions.push((edgeOffset + i * spacing) - length / 2);
    }
    return positions;
  };

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    const tensorPositions = getTensorPositions(length, true, true);
    return (
      <group position={pos} rotation={rot}>
        <mesh 
          onPointerMove={(e) => {
            e.stopPropagation();
            const localPoint = e.point.clone().applyMatrix4(new THREE.Matrix4().copy(e.object.matrixWorld).invert());
            const normalizedPos = (localPoint.x + length / 2) / length;
            setHoveredTrack({ index, pos: Math.max(0, Math.min(1, normalizedPos)) });
          }}
          onPointerOut={() => setHoveredTrack(null)}
          onClick={(e) => {
             if (activeLampType && hoveredTrack?.index === index) {
               onTrackClick(e, index, hoveredTrack.pos);
             }
          }}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial color="#111" roughness={0.8} />
        </mesh>

        {mounting === MountingType.SUSPENDIDO && tensorPositions.map((tensorX, i) => (
          <mesh key={i} position={[tensorX, finalSuspensionHeight / 2, 0]}>
            <cylinderGeometry args={[0.002, 0.002, finalSuspensionHeight]} />
            <meshStandardMaterial color="#999" />
          </mesh>
        ))}

        {activeLampType && hoveredTrack?.index === index && (
          <group position={[hoveredTrack.pos * length - length/2, -railThickness/2, 0]}>
            <LampModel type={activeLampType} isPreview />
          </group>
        )}

        {lamps.filter(l => l.trackIndex === index).map(lamp => (
          <group 
            key={lamp.id} 
            position={[lamp.position * length - length/2, -railThickness/2, 0]}
            rotation={[0, lamp.rotation, 0]}
            onClick={(e) => { e.stopPropagation(); onRemoveLamp(lamp.id); }}
          >
            <LampModel type={lamp.type} />
          </group>
        ))}
      </group>
    );
  };

  return (
    <group position={[0, trackY, 0]}>
      {systemConfig.layout === 'LINEAL' && renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])}
      {systemConfig.layout === 'RECTANGULAR' && (
        <>
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA L' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA U' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
          {renderTrackSegment(2, width, [width / 2, 0, depth], [0, 0, 0])}
        </>
      )}
    </group>
  );
};

