  onUpdatePos: (id: string, pos: [number, number, number]) => void;
  onClone: (id: string) => void;
  onPointerDown: (id: string) => void;
  draggingId: string | null;
}> = ({ config, onUpdatePos, onClone, onPointerDown, draggingId }) => {
  return (
    <group>
      {config.envObjects.map((obj) => (
        <group 
          key={obj.id} 
          position={obj.position}
          onPointerDown={(e) => {
            e.stopPropagation();
            onPointerDown(obj.id);
          }}
          onDoubleClick={(e) => {
            e.stopPropagation();
            onClone(obj.id);
          }}
        >
          {/* Visual indicator when selected/dragging */}
          {draggingId === obj.id && (
            <mesh position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[0.8, 0.85, 32]} />
              <meshBasicMaterial color="black" transparent opacity={0.3} />
            </mesh>
          )}

          <group>
            {obj.type === 'sofa' && <Sofa />}
            {obj.type === 'coffeeTable' && <CoffeeTable />}
            {obj.type === 'officeTable' && <OfficeTable />}
            {obj.type === 'sideboard' && <Sideboard />}
          </group>
        </group>
      ))}
    </group>
  );
};

import React, { useState } from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';
import { ConfigState, LampType, TrackSystemConfig, MountingType } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  systemId: string;
  systemConfig: TrackSystemConfig;
  onTrackClick: (e: ThreeEvent<MouseEvent>, trackIndex: number, pos: number) => void;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
  isSelected: boolean;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, systemId, systemConfig, onTrackClick, activeLampType, onRemoveLamp, isSelected
}) => {
  const { mounting, width, depth, lamps } = systemConfig;
  const { ceilingHeight, suspensionHeight } = config;
  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);

  const trackY = mounting === MountingType.SUSPENDIDO ? ceilingHeight - suspensionHeight : (mounting === MountingType.SUPERFICIAL ? ceilingHeight - 0.02 : ceilingHeight + 0.015);
  const finalSuspensionHeight = mounting === MountingType.SUSPENDIDO ? suspensionHeight : 0;
  const railThickness = 0.04;

  const getTensorPositions = (length: number) => {
    const edgeOffset = 0.15; 
    if (length <= 2 * edgeOffset) return [0];
    const effLength = length - 2 * edgeOffset;
    const maxSpacing = 1.6;
    const numIntervals = Math.max(1, Math.ceil(effLength / maxSpacing));
    const spacing = effLength / numIntervals;
    const positions = [];
    for (let i = 0; i <= numIntervals; i++) {
      positions.push((edgeOffset + i * spacing) - length / 2);
    }
    return positions;
  };

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    const tensorPositions = getTensorPositions(length);
    return (
      <group position={pos} rotation={rot}>
        <mesh 
          onPointerMove={(e) => {
            if (!activeLampType) return;
            e.stopPropagation();
            const localPoint = e.point.clone().applyMatrix4(new THREE.Matrix4().copy(e.object.matrixWorld).invert());
            const normalizedPos = (localPoint.x + length / 2) / length;
            setHoveredTrack({ index, pos: Math.max(0, Math.min(1, normalizedPos)) });
          }}
          onPointerOut={() => setHoveredTrack(null)}
          onClick={(e) => {
             if (activeLampType && hoveredTrack?.index === index) {
               e.stopPropagation();
               onTrackClick(e, index, hoveredTrack.pos);
             }
          }}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial color={isSelected ? "#000" : "#111"} roughness={0.8} />
          {isSelected && (
            <mesh position={[0, 0, 0]}>
              <boxGeometry args={[length + 0.01, railThickness + 0.01, railThickness + 0.01]} />
              <meshBasicMaterial color="black" wireframe transparent opacity={0.1} />
            </mesh>
          )}
        </mesh>

        {mounting === MountingType.SUSPENDIDO && tensorPositions.map((tensorX, i) => (
          <mesh key={i} position={[tensorX, finalSuspensionHeight / 2, 0]}>
            <cylinderGeometry args={[0.002, 0.002, finalSuspensionHeight]} />
            <meshStandardMaterial color="#666" metalness={1} roughness={0} />
          </mesh>
        ))}

        {activeLampType && hoveredTrack?.index === index && (
          <group position={[hoveredTrack.pos * length - length/2, -railThickness/2, 0]}>
            <LampModel type={activeLampType} isPreview />
          </group>
        )}

        {lamps.filter(l => l.trackIndex === index).map(lamp => (
          <group 
            key={lamp.id} 
            position={[lamp.position * length - length/2, -railThickness/2, 0]}
            rotation={[0, lamp.rotation, 0]}
            onClick={(e) => { e.stopPropagation(); onRemoveLamp(lamp.id); }}
          >
            <LampModel type={lamp.type} />
          </group>
        ))}
      </group>
    );
  };

  return (
    <group position={[0, trackY, 0]}>
      {systemConfig.layout === 'LINEAL' && renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])}
      {systemConfig.layout === 'RECTANGULAR' && (
        <>
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA L' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA U' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
          {renderTrackSegment(2, width, [width / 2, 0, depth], [0, 0, 0])}
        </>
      )}
    </group>
  );
};

export enum LayoutType {
  LINEAR = 'LINEAL',
  RECTANGULAR = 'RECTANGULAR',
  L_SHAPE = 'FORMA L',
  U_SHAPE = 'FORMA U'
}

export enum MountingType {
  SUSPENDIDO = 'SUSPENDIDO',
  SUPERFICIAL = 'SUPERFICIAL',
  EMBUTIDO = 'EMBUTIDO'
}

export enum EnvironmentType {
  HOME = 'HOGAR',
  OFFICE = 'OFICINA'
}

export enum LampType {
  SPOT_DIRECTIONAL = 'SPOT_DIRECTIONAL',
  FIXED_RACK = 'FIXED_RACK'
}

export interface PlacedLamp {
  id: string;
  type: LampType;
  trackIndex: number;
  position: number;
  rotation: number;
}

export interface TrackSystemConfig {
  id: string;
  layout: LayoutType;
  mounting: MountingType;
  width: number;
  depth: number;
  position: [number, number, number];
  rotation: number; // 90 degree increments
  lamps: PlacedLamp[];
}

export type EnvObjectType = 'sofa' | 'coffeeTable' | 'officeTable' | 'sideboard' | 'loungeChair' | 'bookshelf';

export interface EnvironmentObject {
  id: string;
  type: EnvObjectType;
  position: [number, number, number];
  rotation: [number, number, number];
}

export interface ConfigState {
  environmentType: EnvironmentType;
  ceilingHeight: number;
  suspensionHeight: number;
  systems: TrackSystemConfig[];
  selectedSystemId: string | null;
  includeInstallation: boolean;
  includeShipping: boolean;
  showEnvironment: boolean;
  envObjects: EnvironmentObject[];
}

export const PRICING = {
  RAIL_KIT_2M: 70,
  SPOT_DIRECTIONAL: 33,
  FIXED_RACK: 60,
  CORNER_PIECE: 25,
  INSTALLATION_BASE: 50,
  INSTALLATION_PER_ITEM: 5,
  SHIPPING: 25
};

export interface ProductDetail {
  id: LampType;
  name: string;
  price: number;
  description: string;
  image: string;
}

