const DEFAULT_HOME: EnvironmentObject[] = [
  { id: 'h1', type: 'sofa', position: [0, 0, -2.5], rotation: [0, 0, 0] },
  { id: 'h2', type: 'coffeeTable', position: [0, 0, -1], rotation: [0, 0, 0] },
  { id: 'h3', type: 'sideboard', position: [2.5, 0, -2.5], rotation: [0, -Math.PI / 2, 0] },
  { id: 'h4', type: 'loungeChair', position: [-2, 0, -1.2], rotation: [0, Math.PI / 4, 0] }
];

const DEFAULT_OFFICE: EnvironmentObject[] = [
  { id: 'o1', type: 'officeTable', position: [0, 0, 0], rotation: [0, 0, 0] },
  { id: 'o2', type: 'officeTable', position: [2.5, 0, 0], rotation: [0, 0, 0] },
  { id: 'o3', type: 'bookshelf', position: [0, 0, -3], rotation: [0, 0, 0] },
  { id: 'o4', type: 'sideboard', position: [-2.5, 0, -2], rotation: [0, Math.PI / 2, 0] }
];

const App: React.FC = () => {
  const initialSystemId = Math.random().toString(36).substr(2, 9);
  const [config, setConfig] = useState<ConfigState>({
    environmentType: EnvironmentType.HOME,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    systems: [{
      id: initialSystemId,
      layout: LayoutType.LINEAR,
      mounting: MountingType.SUSPENDIDO,
      width: 3,
      depth: 2,
      position: [0, 0, 0],
      rotation: 0,
      lamps: []
    }],
    selectedSystemId: initialSystemId,
    includeInstallation: false,
    includeShipping: false,
    showEnvironment: true,
    envObjects: [...DEFAULT_HOME]
  });

  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<LampType | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  useEffect(() => {
    if (config.showEnvironment) {
      setConfig(prev => ({
        ...prev,
        envObjects: prev.environmentType === EnvironmentType.HOME ? [...DEFAULT_HOME] : [...DEFAULT_OFFICE]
      }));
    }
  }, [config.showEnvironment, config.environmentType]);

  const quoteData = useMemo(() => {
    let totalRailLength = 0;
    let totalCorners = 0;
    let totalSpots = 0;
    let totalRacks = 0;

    config.systems.forEach(sys => {
      let l = 0;
      let c = 0;
      switch (sys.layout) {
        case LayoutType.LINEAR: l = sys.width; c = 0; break;
        case LayoutType.RECTANGULAR: l = (sys.width * 2) + (sys.depth * 2); c = 4; break;
        case LayoutType.L_SHAPE: l = sys.width + sys.depth; c = 1; break;
        case LayoutType.U_SHAPE: l = (sys.width * 2) + sys.depth; c = 2; break;
      }
      totalRailLength += l;
      totalCorners += c;
      totalSpots += sys.lamps.filter(lamp => lamp.type === LampType.SPOT_DIRECTIONAL).length;
      totalRacks += sys.lamps.filter(lamp => lamp.type === LampType.FIXED_RACK).length;
    });

    const railSegments = Math.ceil(totalRailLength / 2);
    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const cornersCost = totalCorners * PRICING.CORNER_PIECE;
    const spotsCost = totalSpots * PRICING.SPOT_DIRECTIONAL;
    const racksCost = totalRacks * PRICING.FIXED_RACK;
    const installationCost = config.includeInstallation ? PRICING.INSTALLATION_BASE + ((totalSpots + totalRacks) * PRICING.INSTALLATION_PER_ITEM) : 0;
    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments, railCost, cornerCount: totalCorners, cornersCost, spotCount: totalSpots, spotsCost, rackCount: totalRacks, racksCost,
      installationCost, shippingCost, total: railCost + cornersCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const addLamp = useCallback((type: LampType, systemId: string, trackIndex: number, position: number) => {
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      trackIndex,
      position,
      rotation: type === LampType.SPOT_DIRECTIONAL ? (Math.random() - 0.5) * 2 * Math.PI : 0
    };
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: [...sys.lamps, newLamp] } : sys)
    }));
  }, []);

  const removeLamp = useCallback((systemId: string, lampId: string) => {
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: sys.lamps.filter(l => l.id !== lampId) } : sys)
    }));
  }, []);

  const handleExport3D = async () => {
    if (!sceneGroupRef.current) return;
    const { ColladaExporter } = await import('three/examples/jsm/exporters/ColladaExporter.js');
    const exporter = new ColladaExporter();
    exporter.parse(sceneGroupRef.current, (result) => {
      const blob = new Blob([result.data], { type: 'text/xml' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `eos_riel_sistema.dae`;
      link.click();
    }, { version: '1.4.1' });
  };

  const handleDownloadPDF = () => {
    const canvas = canvasRef.current;
    const imgData = canvas ? canvas.toDataURL('image/png') : '';
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const html = `
      <html>
        <head>
          <title>EOS Iluminación - Cotización Técnica</title>
          <style>
            @page { size: letter; margin: 15mm; }
            body { font-family: 'Inter', sans-serif; color: #1a1a1a; line-height: 1.4; margin: 0; padding: 0; }
            .container { max-width: 800px; margin: auto; }
            .header { display: flex; justify-content: space-between; align-items: flex-start; border-bottom: 2px solid #000; padding-bottom: 15px; margin-bottom: 20px; }
            .logo { height: 60px; }
            .company-info { text-align: right; font-size: 10px; color: #666; }
            .title { font-size: 20px; font-weight: bold; text-transform: uppercase; letter-spacing: 2px; margin: 20px 0 10px 0; }
            .render-box { width: 100%; height: 350px; background: #fdfdfd; border: 1px solid #eee; display: flex; align-items: center; justify-content: center; overflow: hidden; border-radius: 4px; }
            .render-box img { max-width: 100%; max-height: 100%; object-fit: contain; }
            table { width: 100%; border-collapse: collapse; margin: 20px 0; }
            th { background: #f4f4f4; text-align: left; padding: 10px; font-size: 10px; text-transform: uppercase; border-bottom: 1px solid #ddd; }
            td { padding: 10px; border-bottom: 1px solid #eee; font-size: 11px; }
            .total-section { margin-top: 20px; border-top: 2px solid #000; padding-top: 15px; }
            .total-row { display: flex; justify-content: space-between; font-size: 18px; font-weight: bold; }
            .footer { margin-top: 40px; font-size: 9px; color: #999; text-align: center; }
          </style>
        </head>
        <body>
          <div class="container">
            <div class="header">
              <img src="${LOGO_URL}" class="logo" />
              <div class="company-info">
                <strong>EOS Iluminación S.A.</strong><br/>
                Sistemas de Iluminación Arquitectónica Magnética 48V<br/>
                Cotización Técnica #${Math.floor(Math.random()*9000)+1000}<br/>
                Fecha: ${new Date().toLocaleDateString('es-ES')}
              </div>
            </div>
            <div class="title">Configuración de Riel Magnético</div>
            <div class="render-box"><img src="${imgData}" /></div>
            <table>
              <thead>
                <tr>
                  <th>Descripción del Componente</th>
                  <th style="text-align: center">Cant.</th>
                  <th style="text-align: right">Precio Unit.</th>
                  <th style="text-align: right">Subtotal</th>
                </tr>
              </thead>
              <tbody>
                <tr><td>Riel Negro 48V Magnético (Tramos 2000mm)</td><td style="text-align: center">${quoteData.railSegments}</td><td style="text-align: right">$${PRICING.RAIL_KIT_2M}.00</td><td style="text-align: right">$${quoteData.railCost}.00</td></tr>
                ${quoteData.cornerCount > 0 ? `<tr><td>Conector de Esquina L 90° Magnético</td><td style="text-align: center">${quoteData.cornerCount}</td><td style="text-align: right">$${PRICING.CORNER_PIECE}.00</td><td style="text-align: right">$${quoteData.cornersCost}.00</td></tr>` : ''}
                ${quoteData.spotCount > 0 ? `<tr><td>Spot Bala Magnético 12W 4000K</td><td style="text-align: center">${quoteData.spotCount}</td><td style="text-align: right">$${PRICING.SPOT_DIRECTIONAL}.00</td><td style="text-align: right">$${quoteData.spotsCost}.00</td></tr>` : ''}
                ${quoteData.rackCount > 0 ? `<tr><td>Rack Lineal Fijo (8 Luces) Difuso</td><td style="text-align: center">${quoteData.rackCount}</td><td style="text-align: right">$${PRICING.FIXED_RACK}.00</td><td style="text-align: right">$${quoteData.racksCost}.00</td></tr>` : ''}
                ${config.includeInstallation ? `<tr><td>Servicio de Instalación y Calibración</td><td style="text-align: center">1</td><td style="text-align: right">$${quoteData.installationCost}.00</td><td style="text-align: right">$${quoteData.installationCost}.00</td></tr>` : ''}
                ${config.includeShipping ? `<tr><td>Logística y Envío Nacional Asegurado</td><td style="text-align: center">1</td><td style="text-align: right">$${PRICING.SHIPPING}.00</td><td style="text-align: right">$${PRICING.SHIPPING}.00</td></tr>` : ''}
              </tbody>
            </table>
            <div class="total-section"><div class="total-row"><span>TOTAL INVERSIÓN (USD)</span><span>$${quoteData.total.toLocaleString()}.00</span></div></div>
            <div class="footer">Precios sujetos a cambio sin previo aviso. Esta cotización tiene una validez de 15 días. EOS Iluminación - Innovación que trasciende.</div>
          </div>
          <script>setTimeout(() => { window.print(); window.close(); }, 800);</script>
        </body>
      </html>
    `;
    printWindow.document.write(html);
    printWindow.document.close();
  };

  const updateSystemPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ ...prev, systems: prev.systems.map(s => s.id === id ? { ...s, position: newPos } : s) }));
  };

  const updateObjectPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ ...prev, envObjects: prev.envObjects.map(o => o.id === id ? { ...o, position: newPos } : o) }));
  };

  const cloneObject = (id: string) => {
    const obj = config.envObjects.find(o => o.id === id);
    if (!obj) return;
    const newObj: EnvironmentObject = {
      ...obj,
      id: Math.random().toString(36).substr(2, 9),
      position: [obj.position[0] + 0.5, obj.position[1], obj.position[2] + 0.5]
    };
    setConfig(prev => ({ ...prev, envObjects: [...prev.envObjects, newObj] }));
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden relative">
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          canvasRef={canvasRef}
          sceneGroupRef={sceneGroupRef}
          onUpdateSystemPos={updateSystemPosition}
          onUpdateObjectPos={updateObjectPosition}
          onCloneObject={cloneObject}
        />
        <div className="absolute bottom-6 left-6 w-32 opacity-25 pointer-events-none z-0">
