        </div>
        <div>
          <h1 className="font-bold uppercase tracking-tighter text-gray-900 leading-tight">
            Sistema RIEL <br/> <span className="font-light text-gray-400 text-[8px]">by EOS Iluminación</span>
          </h1>
        </div>
      </div>

      <div className="p-4 space-y-4 overflow-y-auto flex-1 scrollbar-hide">
