          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">1. Gestión de Rieles</span>
            <button onClick={addNewSystem} className="bg-black text-white font-bold uppercase text-[7px] px-2 py-1 rounded-full">+ Nuevo</button>
          </div>
          <div className="flex gap-1 overflow-x-auto pb-1 scrollbar-hide">
            {config.systems.map((s, i) => (
              <button key={s.id} onClick={() => updateConfig('selectedSystemId', s.id)} className={`px-4 py-2 border rounded-full text-[8px] uppercase font-bold transition-all shrink-0 ${config.selectedSystemId === s.id ? 'bg-black text-white border-black shadow-md' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-300'}`}>Sistema {i + 1}</button>
