              {Object.values(LayoutType).map(v => (
                <button key={v} onClick={() => updateSelectedSystem('layout', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] ${selectedSystem.layout === v ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100'}`}>{v}</button>
              ))}
            </div>
            <div className="grid grid-cols-3 gap-1">
              {Object.values(MountingType).map(v => (
                <button key={v} onClick={() => updateSelectedSystem('mounting', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] ${selectedSystem.mounting === v ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100'}`}>{v}</button>
              ))}
