                </div>
              )}
            </div>
            <button onClick={rotateSystem} className="w-full py-2 bg-white border border-gray-200 rounded-lg uppercase font-bold text-[7px] hover:border-black transition-all flex items-center justify-center gap-2">
               Rotar 90° ↻
            </button>
