        <section className="space-y-2">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">2. Catálogo de Luces</span>
            {activeLampType && <button onClick={() => setActiveLampType(null)} className="text-red-500 font-bold uppercase text-[7px] animate-pulse">● Soltar</button>}
          </div>
          <div className="grid grid-cols-2 gap-2">
            {[LampType.SPOT_DIRECTIONAL, LampType.FIXED_RACK].map(type => (
              <button key={type} onClick={() => setActiveLampType(type)} className={`flex flex-col p-3 border rounded-2xl transition-all ${activeLampType === type ? 'border-black bg-gray-50 ring-1 ring-black shadow-lg' : 'border-gray-100 hover:border-gray-200 hover:bg-gray-50/50'}`}>
