        </section>

        <section className="space-y-2 bg-gray-900 text-white p-4 rounded-3xl shadow-xl">
          <span className="uppercase font-bold text-gray-500 tracking-widest text-[7px]">3. Cotización Real-Time</span>
          <div className="space-y-1 text-[9px] pt-1">
            <div className="flex justify-between opacity-70"><span>Rieles (2m) x{quoteData.railSegments}</span><span>$${quoteData.railCost}</span></div>
            <div className="flex justify-between opacity-70"><span>Luminarias x{quoteData.spotCount + quoteData.rackCount}</span><span>$${quoteData.spotsCost + quoteData.racksCost}</span></div>
            <div className="flex justify-between opacity-70">
              <label className="flex items-center gap-1 cursor-pointer">
                <input type="checkbox" checked={config.includeInstallation} onChange={e => updateConfig('includeInstallation', e.target.checked)} className="w-2.5 h-2.5 accent-white" />
                <span>Instalación</span>
              </label>
              <span>$${quoteData.installationCost}</span>
            </div>
            <div className="flex justify-between border-t border-gray-800 pt-2 mt-2 font-bold text-sm">
              <span className="text-gray-400 uppercase text-[9px]">Inversión Total</span>
              <span className="text-white">$${quoteData.total.toLocaleString()}</span>
            </div>
          </div>
        </section>
      </div>

      <div className="p-4 bg-white border-t space-y-2">
