        <button onClick={onExport3D} className="w-full py-2.5 border border-gray-200 text-gray-400 font-bold uppercase text-[8px] tracking-widest rounded-xl hover:text-black hover:border-black transition-all">
          Exportar 3D (.DAE)
        </button>
      </div>
    </div>
  );
};

