  onUpdateSystemPos: (id: string, pos: [number, number, number]) => void;
  onUpdateObjectPos: (id: string, pos: [number, number, number]) => void;
  onCloneObject: (id: string) => void;
}

export const Scene3D: React.FC<Scene3DProps> = ({ 
  config, activeLampType, onPlaceLamp, onRemoveLamp, canvasRef, sceneGroupRef,
  onUpdateSystemPos, onUpdateObjectPos, onCloneObject
}) => {
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [dragType, setDragType] = useState<'system' | 'object' | null>(null);

  const onPointerDown = (e: ThreeEvent<PointerEvent>, id: string, type: 'system' | 'object') => {
    e.stopPropagation();
    setDraggingId(id);
    setDragType(type);
  };

  const onPointerUp = () => {
    setDraggingId(null);
    setDragType(null);
  };

  const onPointerMove = (e: ThreeEvent<PointerEvent>) => {
    if (!draggingId || !dragType) return;

    // Al usar un plano capturador, e.point ya nos da la intersección en el mundo
    if (dragType === 'system') {
      onUpdateSystemPos(draggingId, [e.point.x, 0, e.point.z]);
    } else {
      onUpdateObjectPos(draggingId, [e.point.x, 0, e.point.z]);
    }
  };

  return (
    <Canvas 
      shadows 
      className="w-full h-full bg-[#fdfdfd]" 
      ref={canvasRef}
      gl={{ preserveDrawingBuffer: true, antialias: true }}
    >
      <PerspectiveCamera makeDefault position={[8, 5, 8]} fov={35} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 2.15} 
        enableDamping 
        enabled={!draggingId}
        makeDefault
      />

      <ambientLight intensity={0.7} />
      <spotLight position={[10, 20, 10]} angle={0.25} penumbra={1} intensity={2.5} castShadow />

      <Suspense fallback={null}>
        <Environment preset="apartment" />

        {/* Techo - FrontSide solamente */}
        <mesh position={[0, config.ceilingHeight, 0]} rotation={[Math.PI / 2, 0, 0]} receiveShadow>
          <planeGeometry args={[100, 100]} />
          <meshStandardMaterial color="#ffffff" side={THREE.FrontSide} roughness={1} />
        </mesh>

        {/* Plano invisible para capturar el arrastre en el suelo */}
        <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.01, 0]} 
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          onPointerOut={onPointerUp}
          visible={false}
        >
          <planeGeometry args={[1000, 1000]} />
        </mesh>

        <Grid 
          infiniteGrid 
          fadeDistance={40} 
          fadeStrength={10} 
          sectionSize={2} 
          sectionColor="#cfd8dc" 
          sectionThickness={1.2}
          cellSize={0.5} 
          cellColor="#eceff1"
          cellThickness={0.8}
          position={[0, -0.001, 0]}
        />

        {config.showEnvironment && (
          <EnvironmentContext 
            config={config} 
            onPointerDown={(e, id) => onPointerDown(e, id, 'object')}
            onUpdatePos={onUpdateObjectPos} 
            onClone={onCloneObject}
            draggingId={draggingId}
          />
        )}

        <group ref={sceneGroupRef}>
          {config.systems.map((sys) => (
            <group 
              key={sys.id} 
              position={sys.position}
              rotation={[0, sys.rotation, 0]}
              onPointerDown={(e) => onPointerDown(e, sys.id, 'system')}
            >
              <TrackSystem 
                config={config} 
                systemId={sys.id}
                systemConfig={sys}
                onTrackClick={(e, trackIdx, pos) => onPlaceLamp(activeLampType!, sys.id, trackIdx, pos)}
                activeLampType={activeLampType}
                onRemoveLamp={(lampId) => onRemoveLamp(sys.id, lampId)}
                isSelected={config.selectedSystemId === sys.id}
              />
            </group>
          ))}
        </group>

        <ContactShadows position={[0, 0, 0]} opacity={0.25} scale={40} blur={2.5} far={8} />
      </Suspense>
    </Canvas>
  );
};

