              <tbody>
                <tr><td>Riel Negro Magnético (Tramos 2m)</td><td style="text-align:center">${quoteData.railSegments}</td><td style="text-align:right">$${PRICING.RAIL_KIT_2M}.00</td><td style="text-align:right">$${quoteData.railCost}.00</td></tr>
                ${quoteData.cornerCount > 0 ? `<tr><td>Conectores de Esquina L 90°</td><td style="text-align:center">${quoteData.cornerCount}</td><td style="text-align:right">$${PRICING.CORNER_PIECE}.00</td><td style="text-align:right">$${quoteData.cornersCost}.00</td></tr>` : ''}
                ${quoteData.spotCount > 0 ? `<tr><td>Spot Bala Magnético 12W</td><td style="text-align:center">${quoteData.spotCount}</td><td style="text-align:right">$${PRICING.SPOT_DIRECTIONAL}.00</td><td style="text-align:right">$${quoteData.spotsCost}.00</td></tr>` : ''}
