                ${config.includeInstallation ? `<tr><td>Servicio de Instalación Profesional</td><td style="text-align:center">1</td><td style="text-align:right">$${quoteData.installationCost}.00</td><td style="text-align:right">$${quoteData.installationCost}.00</td></tr>` : ''}
