import { ConfigState, LayoutType, MountingType, PlacedLamp, PRICING, LampType, EnvironmentType, TrackSystemConfig, EnvironmentObject, EnvObjectType } from './types';
import * as THREE from 'three';

const LOGO_URL = "https://firebasestorage.googleapis.com/v0/b/clase-22b0d.appspot.com/o/Logo%20EOS.png?alt=media&token=81387693-02f3-424a-939e-4054a1a5b481";

const DEFAULT_HOME: EnvironmentObject[] = [
  { id: 'h1', type: 'sofa', position: [0, 0, -2.5], rotation: [0, 0, 0] },
  { id: 'h2', type: 'coffeeTable', position: [0, 0, -1], rotation: [0, 0, 0] },
  { id: 'h3', type: 'sideboard', position: [2.5, 0, -2.5], rotation: [0, -Math.PI / 2, 0] }
];

const DEFAULT_OFFICE: EnvironmentObject[] = [
  { id: 'o1', type: 'officeTable', position: [0, 0, 0], rotation: [0, 0, 0] },
  { id: 'o2', type: 'officeTable', position: [2.5, 0, 0], rotation: [0, 0, 0] },
  { id: 'o3', type: 'bookshelf', position: [0, 0, -3], rotation: [0, 0, 0] }
];

const App: React.FC = () => {
  const initialSystemId = Math.random().toString(36).substr(2, 9);
  const [config, setConfig] = useState<ConfigState>({
    environmentType: EnvironmentType.HOME,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    systems: [{
      id: initialSystemId,
      layout: LayoutType.LINEAR,
      mounting: MountingType.SUSPENDIDO,
      width: 3,
      depth: 2,
      position: [0, 0, 0],
      rotation: 0,
      lamps: []
    }],
    selectedSystemId: initialSystemId,
    includeInstallation: false,
    includeShipping: false,
    showEnvironment: true,
    envObjects: [...DEFAULT_HOME]
  });

  const [history, setHistory] = useState<ConfigState[]>([]);
  const [deleteMode, setDeleteMode] = useState(false);
  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<LampType | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  // Save to history when config changes (debounced or on specific actions)
  const saveHistory = useCallback((newState: ConfigState) => {
    setHistory(prev => {
      const last = prev[prev.length - 1];
      if (JSON.stringify(last) === JSON.stringify(newState)) return prev;
      return [...prev.slice(-19), newState]; // Keep last 20 steps
    });
  }, []);

  const handleUndo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setHistory(h => h.slice(0, -1));
      setConfig(prev);
    }
  };

  const updateConfig = (key: keyof ConfigState, value: any) => {
    saveHistory(config);
    setConfig(prev => ({ ...prev, [key]: value }));
  };

  const toggleEnvironment = () => {
    saveHistory(config);
    setConfig(prev => ({ ...prev, showEnvironment: !prev.showEnvironment }));
  };

  useEffect(() => {
    // Only reset objects if switching type AND array is empty or user wants reset
    // For now, we only switch if they change environmentType explicitly
  }, [config.environmentType]);

  const handleEnvironmentTypeChange = (type: EnvironmentType) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      environmentType: type,
      envObjects: type === EnvironmentType.HOME ? [...DEFAULT_HOME] : [...DEFAULT_OFFICE]
    }));
  };

  const quoteData = useMemo(() => {
    let totalRailLength = 0;
    let totalCorners = 0;
    let totalSpots = 0;
    let totalRacks = 0;

    config.systems.forEach(sys => {
      let l = 0; let c = 0;
      switch (sys.layout) {
        case LayoutType.LINEAR: l = sys.width; c = 0; break;
        case LayoutType.RECTANGULAR: l = (sys.width * 2) + (sys.depth * 2); c = 4; break;
        case LayoutType.L_SHAPE: l = sys.width + sys.depth; c = 1; break;
        case LayoutType.U_SHAPE: l = (sys.width * 2) + sys.depth; c = 2; break;
      }
      totalRailLength += l; totalCorners += c;
      totalSpots += sys.lamps.filter(lamp => lamp.type === LampType.SPOT_DIRECTIONAL).length;
      totalRacks += sys.lamps.filter(lamp => lamp.type === LampType.FIXED_RACK).length;
    });

    const railSegments = Math.ceil(totalRailLength / 2);
    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const cornersCost = totalCorners * PRICING.CORNER_PIECE;
    const spotsCost = totalSpots * PRICING.SPOT_DIRECTIONAL;
    const racksCost = totalRacks * PRICING.FIXED_RACK;
    const installationCost = config.includeInstallation ? PRICING.INSTALLATION_BASE + ((totalSpots + totalRacks) * PRICING.INSTALLATION_PER_ITEM) : 0;
    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments, railCost, cornerCount: totalCorners, cornersCost, spotCount: totalSpots, spotsCost, rackCount: totalRacks, racksCost,
      installationCost, shippingCost, total: railCost + cornersCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const updateSystemPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ 
      ...prev, 
      systems: prev.systems.map(s => s.id === id ? { ...s, position: newPos } : s) 
    }));
  };

  const updateObjectPosition = (id: string, newPos: [number, number, number]) => {
    // We only update X and Z, keeping Y as is
    setConfig(prev => ({ 
      ...prev, 
      envObjects: prev.envObjects.map(o => o.id === id ? { ...o, position: [newPos[0], o.position[1], newPos[2]] } : o) 
    }));
  };

  const deleteObject = (id: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      envObjects: prev.envObjects.filter(o => o.id !== id)
    }));
  };

  const addLamp = useCallback((type: LampType, systemId: string, trackIndex: number, position: number) => {
    saveHistory(config);
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type, trackIndex, position,
      rotation: type === LampType.SPOT_DIRECTIONAL ? (Math.random() - 0.5) * 2 * Math.PI : 0
    };
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: [...sys.lamps, newLamp] } : sys)
    }));
  }, [config, saveHistory]);

  const removeLamp = useCallback((systemId: string, lampId: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: sys.lamps.filter(l => l.id !== lampId) } : sys)
    }));
  }, [config, saveHistory]);

  const cloneObject = (id: string) => {
    saveHistory(config);
    const obj = config.envObjects.find(o => o.id === id);
    if (!obj) return;
    const newObj: EnvironmentObject = {
      ...obj,
      id: Math.random().toString(36).substr(2, 9),
      position: [obj.position[0] + 0.5, obj.position[1], obj.position[2] + 0.5]
    };
    setConfig(prev => ({ ...prev, envObjects: [...prev.envObjects, newObj] }));
  };

  const handleExport3D = async () => {
    if (!sceneGroupRef.current) return;
    const { ColladaExporter } = await import('three/examples/jsm/exporters/ColladaExporter.js');
    const exporter = new ColladaExporter();
    exporter.parse(sceneGroupRef.current, (result) => {
      const blob = new Blob([result.data], { type: 'text/xml' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `eos_iluminacion_3d.dae`;
      link.click();
    }, { version: '1.4.1' });
  };

  const handleDownloadPDF = () => {
    const canvas = canvasRef.current;
    const imgData = canvas ? canvas.toDataURL('image/png') : '';
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const html = `
      <html>
        <head>
          <title>EOS Iluminación - Cotización Formal</title>
          <style>
            @page { size: letter; margin: 15mm; }
            body { font-family: 'Inter', sans-serif; color: #1a1a1a; margin: 0; padding: 0; }
            .letter { width: 195mm; margin: auto; padding: 10mm; border: 1px solid #eee; }
            .header { display: flex; justify-content: space-between; border-bottom: 2px solid #000; padding-bottom: 15px; margin-bottom: 25px; }
            .logo { height: 70px; }
            .company-details { text-align: right; font-size: 10px; color: #666; }
            .render-container { width: 100%; height: 320px; background: #fdfdfd; border-radius: 8px; border: 1px solid #eee; margin-bottom: 25px; display: flex; align-items: center; justify-content: center; overflow: hidden; }
            .render-container img { max-width: 100%; max-height: 100%; object-fit: contain; }
            .section-title { font-size: 12px; font-weight: bold; text-transform: uppercase; letter-spacing: 1px; margin-bottom: 10px; border-left: 3px solid #000; padding-left: 10px; }
            table { width: 100%; border-collapse: collapse; margin-bottom: 25px; }
            th { text-align: left; background: #f4f4f4; padding: 10px; font-size: 9px; text-transform: uppercase; }
            td { padding: 10px; border-bottom: 1px solid #eee; font-size: 11px; }
            .totals { float: right; width: 250px; border-top: 2px solid #000; padding-top: 10px; }
            .total-row { display: flex; justify-content: space-between; margin-bottom: 5px; }
            .final-total { font-size: 18px; font-weight: bold; margin-top: 10px; }
            .footer { margin-top: 50px; font-size: 8px; color: #999; text-align: center; border-top: 1px solid #eee; padding-top: 10px; }
          </style>
        </head>
        <body>
          <div class="letter">
            <div class="header">
              <img src="${LOGO_URL}" class="logo" />
              <div class="company-details">
                <strong>EOS ILUMINACIÓN S.A.</strong><br/>
                Sistemas de Riel Magnético 48V<br/>
                Cotización #${Math.floor(Math.random()*10000)}<br/>
                Fecha: ${new Date().toLocaleDateString('es-ES')}
              </div>
            </div>

            <div class="section-title">Vista Previa de Configuración</div>
            <div class="render-container"><img src="${imgData}" /></div>

            <div class="section-title">Detalle de Materiales y Servicios</div>
            <table>
              <thead>
                <tr>
                  <th>Componente</th>
                  <th style="text-align: center">Cant.</th>
                  <th style="text-align: right">Unitario</th>
                  <th style="text-align: right">Total</th>
                </tr>
              </thead>
              <tbody>
                <tr><td>Riel Negro Magnético (Tramos 2m)</td><td style="text-align:center">${quoteData.railSegments}</td><td style="text-align:right">$${PRICING.RAIL_KIT_2M}.00</td><td style="text-align:right">$${quoteData.railCost}.00</td></tr>
                ${quoteData.cornerCount > 0 ? `<tr><td>Conectores de Esquina L 90°</td><td style="text-align:center">${quoteData.cornerCount}</td><td style="text-align:right">$${PRICING.CORNER_PIECE}.00</td><td style="text-align:right">$${quoteData.cornersCost}.00</td></tr>` : ''}
                ${quoteData.spotCount > 0 ? `<tr><td>Spot Bala Magnético 12W</td><td style="text-align:center">${quoteData.spotCount}</td><td style="text-align:right">$${PRICING.SPOT_DIRECTIONAL}.00</td><td style="text-align:right">$${quoteData.spotsCost}.00</td></tr>` : ''}
                ${quoteData.rackCount > 0 ? `<tr><td>Rack Lineal 8 Luces Difuso</td><td style="text-align:center">${quoteData.rackCount}</td><td style="text-align:right">$${PRICING.FIXED_RACK}.00</td><td style="text-align:right">$${quoteData.racksCost}.00</td></tr>` : ''}
                ${config.includeInstallation ? `<tr><td>Servicio de Instalación Profesional</td><td style="text-align:center">1</td><td style="text-align:right">$${quoteData.installationCost}.00</td><td style="text-align:right">$${quoteData.installationCost}.00</td></tr>` : ''}
                ${config.includeShipping ? `<tr><td>Logística y Envío Asegurado</td><td style="text-align:center">1</td><td style="text-align:right">$${PRICING.SHIPPING}.00</td><td style="text-align:right">$${PRICING.SHIPPING}.00</td></tr>` : ''}
              </tbody>
            </table>

            <div class="totals">
              <div class="total-row"><span>Subtotal Materiales</span><span>$${quoteData.railCost + quoteData.cornersCost + quoteData.spotsCost + quoteData.racksCost}.00</span></div>
              <div class="total-row"><span>Servicios Adicionales</span><span>$${quoteData.installationCost + quoteData.shippingCost}.00</span></div>
              <div class="total-row final-total"><span>TOTAL (USD)</span><span>$${quoteData.total.toLocaleString()}.00</span></div>
            </div>

            <div class="footer">
              Validez de la oferta: 15 días naturales. Precios no incluyen impuestos locales.<br/>
              EOS Iluminación - Transformando espacios con luz inteligente.
            </div>
          </div>
          <script>setTimeout(() => { window.print(); window.close(); }, 800);</script>
        </body>
      </html>
    `;
    printWindow.document.write(html);
    printWindow.document.close();
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden relative">
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          canvasRef={canvasRef}
          sceneGroupRef={sceneGroupRef}
          onUpdateSystemPos={updateSystemPosition}
          onUpdateObjectPos={updateObjectPosition}
          onCloneObject={cloneObject}
          onDeleteObject={deleteObject}
          deleteMode={deleteMode}
        />
        {/* Marca de agua optimizada */}
        <div className="absolute bottom-8 left-8 w-48 opacity-25 pointer-events-none z-10">
          <img 
            src={LOGO_URL} 
            alt="EOS Logo" 
            className="w-full h-auto" 
            onError={(e) => {
              // Fallback just in case firebasestorage is tricky
              e.currentTarget.style.display = 'none';
            }}
          />
        </div>
      </div>
      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        updateConfig={updateConfig}
        quoteData={quoteData}
        activeLampType={activeLampType} 
        setActiveLampType={setActiveLampType}
        onDownloadPDF={handleDownloadPDF} 
        onExport3D={handleExport3D}
        onProductDetail={setSelectedProduct}
        logoUrl={LOGO_URL}
        onUndo={handleUndo}
        canUndo={history.length > 0}
        onToggleEnv={toggleEnvironment}
        deleteMode={deleteMode}
        setDeleteMode={setDeleteMode}
        onEnvTypeChange={handleEnvironmentTypeChange}
      />
      <ProductModal productType={selectedProduct} onClose={() => setSelectedProduct(null)} />
    </div>
  );
};

export default App;

import React from 'react';
import { ConfigState, LayoutType, LampType, MountingType, EnvironmentType, PRICING, TrackSystemConfig } from '../types';

interface SidebarProps {
  config: ConfigState;
  setConfig: React.Dispatch<React.SetStateAction<ConfigState>>;
  updateConfig: (key: keyof ConfigState, value: any) => void;
  quoteData: any;
  activeLampType: LampType | null;
  setActiveLampType: (type: LampType | null) => void;
  onDownloadPDF: () => void;
  onExport3D: () => void;
  onProductDetail: (type: LampType) => void;
  logoUrl: string;
  onUndo: () => void;
  canUndo: boolean;
  onToggleEnv: () => void;
  deleteMode: boolean;
  setDeleteMode: (val: boolean) => void;
  onEnvTypeChange: (type: EnvironmentType) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  config, setConfig, updateConfig, quoteData, activeLampType, setActiveLampType, 
  onDownloadPDF, onExport3D, onProductDetail, logoUrl, onUndo, canUndo, 
  onToggleEnv, deleteMode, setDeleteMode, onEnvTypeChange
}) => {
  const selectedSystem = config.systems.find(s => s.id === config.selectedSystemId);

  const updateSelectedSystem = (key: keyof TrackSystemConfig, value: any) => {
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(s => s.id === config.selectedSystemId ? { ...s, [key]: value } : s)
    }));
  };

  const addNewSystem = () => {
    const id = Math.random().toString(36).substr(2, 9);
    setConfig(prev => ({
      ...prev,
      systems: [...prev.systems, {
        id, layout: LayoutType.LINEAR, mounting: MountingType.SUSPENDIDO,
        width: 2, depth: 2, position: [Math.random() * 2, 0, Math.random() * 2], rotation: 0, lamps: []
      }],
      selectedSystemId: id
    }));
  };

  const rotateSystem = () => {
    if (selectedSystem) {
      updateSelectedSystem('rotation', (selectedSystem.rotation || 0) + Math.PI / 2);
    }
  };

  return (
    <div className="w-[340px] bg-white border-l flex flex-col h-full z-20 text-[10px] shadow-2xl">
      <div className="p-4 border-b flex items-center justify-between bg-gray-50/50">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 flex items-center justify-center bg-white rounded-lg shadow-sm p-1">
            <img src={logoUrl} alt="EOS" className="max-h-full max-w-full object-contain" />
          </div>
          <div>
            <h1 className="font-bold uppercase tracking-tighter text-gray-900 leading-tight">
              Configurador <br/> <span className="font-light text-gray-400 text-[8px]">EOS Iluminación</span>
            </h1>
          </div>
        </div>
        <button 
          onClick={onUndo} 
          disabled={!canUndo}
          className={`p-2 rounded-full border transition-all ${canUndo ? 'border-gray-300 text-black hover:bg-gray-100' : 'border-gray-100 text-gray-200 cursor-not-allowed'}`}
          title="Deshacer"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
        </button>
      </div>

      <div className="p-4 space-y-4 overflow-y-auto flex-1 scrollbar-hide">
        {/* Environment Control */}
        <section className="space-y-2">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Entorno</span>
            <div className="flex gap-2">
              <button 
                onClick={onToggleEnv} 
                className={`px-3 py-1 rounded-full border text-[7px] uppercase font-bold transition-all ${config.showEnvironment ? 'bg-green-500 border-green-500 text-white' : 'bg-white text-gray-400'}`}
              >
                {config.showEnvironment ? 'Visible' : 'Oculto'}
              </button>
              <button 
                onClick={() => setDeleteMode(!deleteMode)} 
                className={`px-3 py-1 rounded-full border text-[7px] uppercase font-bold transition-all ${deleteMode ? 'bg-red-500 border-red-500 text-white' : 'bg-white text-gray-400'}`}
              >
                Borrar Mobiliario
              </button>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-1">
            {Object.values(EnvironmentType).map(type => (
              <button 
                key={type} 
                onClick={() => onEnvTypeChange(type)}
                className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] ${config.environmentType === type ? 'bg-black text-white' : 'bg-white text-gray-400 border-gray-100'}`}
              >
                {type}
              </button>
            ))}
          </div>
        </section>

        <section className="space-y-2">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Sistemas de Riel</span>
            <button onClick={addNewSystem} className="bg-black text-white font-bold uppercase text-[7px] px-2 py-1 rounded-full">+ Nuevo</button>
          </div>
          <div className="flex gap-1 overflow-x-auto pb-1 scrollbar-hide">
            {config.systems.map((s, i) => (
              <button key={s.id} onClick={() => updateConfig('selectedSystemId', s.id)} className={`px-4 py-2 border rounded-full text-[8px] uppercase font-bold transition-all shrink-0 ${config.selectedSystemId === s.id ? 'bg-black text-white border-black shadow-md' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-300'}`}>Sistema {i + 1}</button>
            ))}
          </div>
        </section>

        {selectedSystem && (
          <div className="space-y-3 p-3 bg-gray-50 rounded-2xl border border-gray-100">
            <div className="grid grid-cols-2 gap-1">
              {Object.values(LayoutType).map(v => (
                <button key={v} onClick={() => updateSelectedSystem('layout', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] ${selectedSystem.layout === v ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100'}`}>{v}</button>
              ))}
            </div>
            <div className="grid grid-cols-3 gap-1">
              {Object.values(MountingType).map(v => (
                <button key={v} onClick={() => updateSelectedSystem('mounting', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] ${selectedSystem.mounting === v ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100'}`}>{v}</button>
              ))}
            </div>
            <div className="space-y-2 py-1">
              <div className="flex items-center gap-2">
                <span className="w-12 text-[7px] uppercase font-bold text-gray-400">Ancho</span>
                <input type="range" min="1" max="10" step="0.5" value={selectedSystem.width} onChange={e => updateSelectedSystem('width', parseFloat(e.target.value))} className="flex-1 accent-black h-1" />
                <span className="w-8 text-right font-bold text-[9px]">{selectedSystem.width}m</span>
              </div>
              {selectedSystem.layout !== LayoutType.LINEAR && (
                <div className="flex items-center gap-2">
                  <span className="w-12 text-[7px] uppercase font-bold text-gray-400">Fondo</span>
                  <input type="range" min="1" max="10" step="0.5" value={selectedSystem.depth} onChange={e => updateSelectedSystem('depth', parseFloat(e.target.value))} className="flex-1 accent-black h-1" />
                  <span className="w-8 text-right font-bold text-[9px]">{selectedSystem.depth}m</span>
                </div>
              )}
            </div>
            <button onClick={rotateSystem} className="w-full py-2 bg-white border border-gray-200 rounded-lg uppercase font-bold text-[7px] hover:border-black transition-all flex items-center justify-center gap-2">
               Rotar 90° ↻
            </button>
          </div>
        )}

        <section className="space-y-2">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Luminarias</span>
            {activeLampType && <button onClick={() => setActiveLampType(null)} className="text-red-500 font-bold uppercase text-[7px] animate-pulse">● Soltar</button>}
          </div>
          <div className="grid grid-cols-2 gap-2">
            {[LampType.SPOT_DIRECTIONAL, LampType.FIXED_RACK].map(type => (
              <button key={type} onClick={() => setActiveLampType(type)} className={`flex flex-col p-3 border rounded-2xl transition-all ${activeLampType === type ? 'border-black bg-gray-50 ring-1 ring-black shadow-lg' : 'border-gray-100 hover:border-gray-200 hover:bg-gray-50/50'}`}>
                <div className="flex justify-between items-start mb-2 w-full">
                  <div className="w-5 h-5 bg-black rounded-full" />
                  <div onClick={(e) => { e.stopPropagation(); onProductDetail(type); }} className="w-5 h-5 flex items-center justify-center text-[7px] bg-gray-100 rounded-full hover:bg-black hover:text-white">i</div>
                </div>
                <p className="font-bold text-[8px] uppercase">{type === LampType.SPOT_DIRECTIONAL ? 'Spot Bala 12W' : 'Rack 8 Luces'}</p>
                <p className="text-[8px] text-gray-400 font-medium">$${type === LampType.SPOT_DIRECTIONAL ? PRICING.SPOT_DIRECTIONAL : PRICING.FIXED_RACK}.00</p>
              </button>
            ))}
          </div>
        </section>

        <section className="space-y-3 bg-gray-900 text-white p-4 rounded-3xl shadow-xl">
