export const EnvironmentContext: React.FC<{ 
  config: ConfigState; 
  onUpdatePos: (id: string, pos: [number, number, number]) => void;
  onClone: (id: string) => void;
  onPointerDown: (e: ThreeEvent<PointerEvent>, id: string) => void;
  draggingId: string | null;
  deleteMode?: boolean;
  selectedObjectId: string | null;
}> = ({ config, onPointerDown, draggingId, deleteMode, selectedObjectId }) => {
  return (
    <group>
      {config.envObjects.map((obj) => (
        <group 
          key={obj.id} 
          position={obj.position}
          rotation={obj.rotation}
          onPointerDown={(e) => { e.stopPropagation(); onPointerDown(e, obj.id); }}
        >
          {/* Selection highlight circle */}
          {(selectedObjectId === obj.id || draggingId === obj.id) && !deleteMode && (
            <mesh position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[1.2, 1.25, 48]} />
              <meshBasicMaterial color="#00ff00" transparent opacity={0.4} />
            </mesh>
          )}
          {deleteMode && (
             <mesh position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
                <ringGeometry args={[1.2, 1.25, 48]} />
                <meshBasicMaterial color="#ff0000" transparent opacity={0.6} />
             </mesh>
          )}
          <group>
            {obj.type === 'sofa' && <Sofa />}
            {obj.type === 'coffeeTable' && <CoffeeTable />}
            {obj.type === 'officeTable' && <OfficeTable />}
            {obj.type === 'sideboard' && <Sideboard />}
            {obj.type === 'loungeChair' && <LoungeChair />}
            {obj.type === 'bookshelf' && <Bookshelf />}
            {obj.type === 'lowCabinet' && <LowCabinet />}
          </group>
        </group>
      ))}
    </group>
  );
};

import React from 'react';
import { ConfigState, LayoutType, LampType, MountingType, EnvironmentType, PRICING, TrackSystemConfig } from '../types';

interface SidebarProps {
  config: ConfigState;
  setConfig: React.Dispatch<React.SetStateAction<ConfigState>>;
  updateConfig: (key: keyof ConfigState, value: any) => void;
  quoteData: any;
  activeLampType: LampType | null;
  setActiveLampType: (type: LampType | null) => void;
  onDownloadPDF: () => void;
  onExport3D: () => void;
  onProductDetail: (type: LampType) => void;
  logoUrl: string;
  onUndo: () => void;
  canUndo: boolean;
  onToggleEnv: () => void;
  deleteMode: boolean;
  setDeleteMode: (val: boolean) => void;
  onEnvTypeChange: (type: EnvironmentType) => void;
  onRotateObject: (id: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  config, setConfig, updateConfig, quoteData, activeLampType, setActiveLampType, 
  onDownloadPDF, onExport3D, onProductDetail, logoUrl, onUndo, canUndo, 
  onToggleEnv, deleteMode, setDeleteMode, onEnvTypeChange, onRotateObject
}) => {
  const selectedSystem = config.systems.find(s => s.id === config.selectedSystemId);
  const selectedObject = config.envObjects.find(o => o.id === config.selectedObjectId);

  const updateSelectedSystem = (key: keyof TrackSystemConfig, value: any) => {
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(s => s.id === config.selectedSystemId ? { ...s, [key]: value } : s)
    }));
  };

  const addNewSystem = () => {
    const id = Math.random().toString(36).substr(2, 9);
    setConfig(prev => ({
      ...prev,
      systems: [...prev.systems, {
        id, layout: LayoutType.LINEAR, mounting: MountingType.SUSPENDIDO,
        width: 2, depth: 2, position: [Math.random() * 2, 0, Math.random() * 2], rotation: 0, lamps: []
      }],
      selectedSystemId: id
    }));
  };

  const rotateSystem = () => {
    if (selectedSystem) {
      updateSelectedSystem('rotation', (selectedSystem.rotation || 0) + Math.PI / 2);
    }
  };

  return (
    <div className="w-[340px] bg-white border-l flex flex-col h-full z-20 text-[10px] shadow-2xl">
      {/* Header with Logo and Undo */}
      <div className="p-4 border-b flex items-center justify-between bg-white">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 flex items-center justify-center bg-white rounded-lg p-0.5 border border-gray-50">
            <img src={logoUrl} alt="EOS" className="max-h-full max-w-full object-contain" crossOrigin="anonymous" />
          </div>
          <div>
            <h1 className="font-bold uppercase tracking-tighter text-gray-900 leading-tight">
              Configurador <br/> <span className="font-light text-gray-400 text-[8px]">EOS Iluminación</span>
            </h1>
          </div>
        </div>
        <button 
          onClick={onUndo} 
          disabled={!canUndo}
          className={`p-2 rounded-full border transition-all ${canUndo ? 'border-gray-300 text-black hover:bg-gray-100 active:scale-95' : 'border-gray-100 text-gray-200 cursor-not-allowed'}`}
          title="Deshacer"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
        </button>
      </div>

      <div className="p-4 space-y-5 overflow-y-auto flex-1 scrollbar-hide">
        {/* Environment Control Section (Matched to Screenshot) */}
        <section className="space-y-2">
          <div className="flex items-center justify-between">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Entorno</span>
            <div className="flex gap-1">
              <button 
                onClick={onToggleEnv} 
                className={`px-3 py-1 rounded-full border text-[7px] font-bold transition-all ${config.showEnvironment ? 'bg-[#22c55e] border-[#22c55e] text-white' : 'bg-white text-gray-400 border-gray-200'}`}
              >
                VISIBLE
              </button>
              <button 
                onClick={() => setDeleteMode(!deleteMode)} 
                className={`px-3 py-1 rounded-full border text-[7px] font-bold transition-all ${deleteMode ? 'bg-[#ef4444] border-[#ef4444] text-white shadow-sm' : 'bg-white text-gray-400 border-gray-200 hover:border-gray-400'}`}
              >
                BORRAR MOBILIARIO
              </button>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-1">
            {Object.values(EnvironmentType).map(type => (
              <button 
                key={type} 
                onClick={() => onEnvTypeChange(type)}
                className={`py-2 border rounded-lg uppercase font-bold text-[8px] transition-all ${config.environmentType === type ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-200'}`}
              >
                {type}
              </button>
            ))}
          </div>
          {selectedObject && (
            <button 
              onClick={() => onRotateObject(selectedObject.id)}
              className="w-full py-2 bg-gray-50 border border-gray-200 rounded-lg uppercase font-bold text-[7px] hover:border-black active:bg-gray-200 transition-all flex items-center justify-center gap-2"
            >
              Rotar Objeto Seleccionado 90° ↻
            </button>
          )}
        </section>

        {/* Systems Section */}
        <section className="space-y-2 pt-2 border-t border-gray-50">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Sistemas de Riel</span>
            <button onClick={addNewSystem} className="bg-black text-white font-bold uppercase text-[7px] px-2 py-1 rounded-full hover:scale-105 transition-transform">+ Nuevo</button>
          </div>
          <div className="flex gap-1 overflow-x-auto pb-1 scrollbar-hide">
            {config.systems.map((s, i) => (
              <button key={s.id} onClick={() => updateConfig('selectedSystemId', s.id)} className={`px-4 py-2 border rounded-full text-[8px] uppercase font-bold transition-all shrink-0 ${config.selectedSystemId === s.id ? 'bg-black text-white border-black shadow-md' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-300'}`}>Sistema {i + 1}</button>
            ))}
          </div>
        </section>

        {selectedSystem && (
          <div className="space-y-3 p-3 bg-gray-50 rounded-2xl border border-gray-100 animate-in fade-in slide-in-from-top-2 duration-300">
            <div className="grid grid-cols-2 gap-1">
              {Object.values(LayoutType).map(v => (
                <button key={v} onClick={() => updateSelectedSystem('layout', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] transition-all ${selectedSystem.layout === v ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100 hover:bg-white'}`}>{v}</button>
              ))}
            </div>
            <div className="grid grid-cols-3 gap-1">
              {Object.values(MountingType).map(v => (
                <button key={v} onClick={() => updateSelectedSystem('mounting', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] transition-all ${selectedSystem.mounting === v ? 'bg-black text-white border-black shadow-sm' : 'bg-white text-gray-400 border-gray-100 hover:bg-white'}`}>{v}</button>
              ))}
            </div>
            <div className="space-y-2 py-1 px-1">
              <div className="flex items-center gap-2">
                <span className="w-12 text-[7px] uppercase font-bold text-gray-400">Ancho</span>
                <input type="range" min="1" max="10" step="0.5" value={selectedSystem.width} onChange={e => updateSelectedSystem('width', parseFloat(e.target.value))} className="flex-1 accent-black h-1" />
                <span className="w-8 text-right font-bold text-[9px]">{selectedSystem.width}m</span>
              </div>
              {selectedSystem.layout !== LayoutType.LINEAR && (
                <div className="flex items-center gap-2">
                  <span className="w-12 text-[7px] uppercase font-bold text-gray-400">Fondo</span>
                  <input type="range" min="1" max="10" step="0.5" value={selectedSystem.depth} onChange={e => updateSelectedSystem('depth', parseFloat(e.target.value))} className="flex-1 accent-black h-1" />
                  <span className="w-8 text-right font-bold text-[9px]">{selectedSystem.depth}m</span>
                </div>
              )}
            </div>
            <button onClick={rotateSystem} className="w-full py-2 bg-white border border-gray-200 rounded-lg uppercase font-bold text-[7px] hover:border-black transition-all flex items-center justify-center gap-2 active:scale-[0.98]">
               Rotar Riel 90° ↻
            </button>
          </div>
        )}

        {/* Luminaires Section */}
        <section className="space-y-2">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Luminarias</span>
            {activeLampType && <button onClick={() => setActiveLampType(null)} className="text-red-500 font-bold uppercase text-[7px] animate-pulse">● Soltar</button>}
          </div>
          <div className="grid grid-cols-2 gap-2">
            {[LampType.SPOT_DIRECTIONAL, LampType.FIXED_RACK].map(type => (
              <button key={type} onClick={() => setActiveLampType(type)} className={`flex flex-col p-3 border rounded-2xl transition-all group ${activeLampType === type ? 'border-black bg-gray-50 ring-1 ring-black shadow-lg' : 'border-gray-100 hover:border-gray-200 hover:bg-gray-50/50'}`}>
                <div className="flex justify-between items-start mb-2 w-full">
                  <div className={`w-5 h-5 rounded-full transition-colors ${activeLampType === type ? 'bg-[#22c55e]' : 'bg-black'}`} />
                  <div onClick={(e) => { e.stopPropagation(); onProductDetail(type); }} className="w-5 h-5 flex items-center justify-center text-[7px] bg-gray-100 rounded-full hover:bg-black hover:text-white border border-transparent hover:border-black">i</div>
                </div>
                <p className="font-bold text-[8px] uppercase">{type === LampType.SPOT_DIRECTIONAL ? 'Spot Bala 12W' : 'Rack 8 Luces'}</p>
                <p className="text-[8px] text-gray-400 font-medium">$${type === LampType.SPOT_DIRECTIONAL ? PRICING.SPOT_DIRECTIONAL : PRICING.FIXED_RACK}.00</p>
              </button>
            ))}
          </div>
        </section>

        {/* Quotation Panel */}
        <section className="space-y-3 bg-gray-900 text-white p-4 rounded-3xl shadow-xl">
          <span className="uppercase font-bold text-gray-500 tracking-widest text-[7px]">Cotización</span>

          <div className="space-y-2">
             <label className="flex items-center justify-between p-2 rounded-xl bg-gray-800 border border-gray-700 cursor-pointer group transition-all hover:bg-gray-750">
                <div className="flex items-center gap-2">
                  <input type="checkbox" checked={config.includeInstallation} onChange={e => updateConfig('includeInstallation', e.target.checked)} className="w-4 h-4 accent-white rounded-md cursor-pointer" />
                  <div>
                    <span className="block font-bold text-[9px] uppercase">Instalación</span>
                    <span className="block text-[7px] text-gray-400">Personal especializado</span>
                  </div>
                </div>
                <span className="font-bold text-[9px]">$${quoteData.installationCost}</span>
             </label>

             <label className="flex items-center justify-between p-2 rounded-xl bg-gray-800 border border-gray-700 cursor-pointer group transition-all hover:bg-gray-750">
                <div className="flex items-center gap-2">
                  <input type="checkbox" checked={config.includeShipping} onChange={e => updateConfig('includeShipping', e.target.checked)} className="w-4 h-4 accent-white rounded-md cursor-pointer" />
                  <div>
                    <span className="block font-bold text-[9px] uppercase">Transporte</span>
                    <span className="block text-[7px] text-gray-400">Envío nacional asegurado</span>
                  </div>
                </div>
                <span className="font-bold text-[9px]">$${quoteData.shippingCost}</span>
             </label>
          </div>

          <div className="space-y-1 text-[9px] pt-2 border-t border-gray-800">
            <div className="flex justify-between opacity-70"><span>Materiales (Rieles + Luces)</span><span>$${quoteData.railCost + quoteData.cornersCost + quoteData.spotsCost + quoteData.racksCost}</span></div>
            <div className="flex justify-between font-bold text-sm mt-1">
              <span className="text-gray-400 uppercase text-[9px]">Total (USD)</span>
              <span className="text-white">$${quoteData.total.toLocaleString()}</span>
            </div>
          </div>
        </section>
      </div>

      <div className="p-4 bg-white border-t space-y-2">
        <button onClick={onDownloadPDF} className="w-full py-3.5 bg-black text-white font-bold uppercase text-[9px] tracking-widest rounded-xl hover:bg-gray-800 transition-all flex items-center justify-center gap-2 shadow-lg active:scale-[0.99]">
          Generar PDF Formal
        </button>
        <button onClick={onExport3D} className="w-full py-2.5 border border-gray-200 text-gray-400 font-bold uppercase text-[8px] tracking-widest rounded-xl hover:text-black hover:border-black transition-all">
          Exportar 3D (.DAE)
        </button>
      </div>
    </div>
  );
};

