          {/* Selection highlight ring */}
          {(selectedObjectId === obj.id || draggingId === obj.id) && !deleteMode && (
            <group position={[0, 0.005, 0]}>
              <mesh rotation={[-Math.PI / 2, 0, 0]}>
                <ringGeometry args={[1.25, 1.28, 64]} />
