import React, { useState, useRef } from 'react';
import * as THREE from 'three';
import { ThreeEvent, useFrame } from '@react-three/fiber';
import { ConfigState, LampType, TrackSystemConfig, MountingType } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  systemId: string;
  systemConfig: TrackSystemConfig;
  onTrackClick: (e: ThreeEvent<MouseEvent>, trackIndex: number, pos: number) => void;
  onUpdateLampPos: (systemId: string, lampId: string, newPos: number) => void;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
  isSelected: boolean;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, systemId, systemConfig, onTrackClick, onUpdateLampPos, activeLampType, onRemoveLamp, isSelected
}) => {
  const { mounting, width, depth, lamps } = systemConfig;
  const { ceilingHeight, suspensionHeight } = config;
  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);
  const [draggingLamp, setDraggingLamp] = useState<{ id: string, trackIndex: number } | null>(null);

  const trackY = mounting === MountingType.SUSPENDIDO ? ceilingHeight - suspensionHeight : (mounting === MountingType.SUPERFICIAL ? ceilingHeight - 0.02 : ceilingHeight + 0.015);
  const railThickness = 0.04;

  const handlePointerMove = (e: ThreeEvent<PointerEvent>, index: number, length: number) => {
    e.stopPropagation();
    const localPoint = e.point.clone().applyMatrix4(new THREE.Matrix4().copy(e.object.matrixWorld).invert());
    const normalizedPos = Math.max(0, Math.min(1, (localPoint.x + length / 2) / length));

    if (draggingLamp && draggingLamp.trackIndex === index) {
      onUpdateLampPos(systemId, draggingLamp.id, normalizedPos);
    } else if (activeLampType) {
      setHoveredTrack({ index, pos: normalizedPos });
    }
  };

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    return (
      <group position={pos} rotation={rot}>
        <mesh 
          onPointerMove={(e) => handlePointerMove(e, index, length)}
          onPointerOut={() => setHoveredTrack(null)}
          onPointerUp={() => setDraggingLamp(null)}
          onClick={(e) => {
             if (activeLampType && hoveredTrack?.index === index) {
               e.stopPropagation();
               onTrackClick(e as any, index, hoveredTrack.pos);
             }
          }}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial color={isSelected ? "#000" : "#111"} roughness={0.8} />
        </mesh>

        {activeLampType && hoveredTrack?.index === index && !draggingLamp && (
          <group position={[hoveredTrack.pos * length - length/2, -railThickness/2, 0]}>
            <LampModel type={activeLampType} isPreview />
          </group>
        )}

        {lamps.filter(l => l.trackIndex === index).map(lamp => (
          <group 
            key={lamp.id} 
            position={[lamp.position * length - length/2, -railThickness/2, 0]}
            rotation={[0, lamp.rotation, 0]}
            onPointerDown={(e) => {
              e.stopPropagation();
              setDraggingLamp({ id: lamp.id, trackIndex: index });
            }}
            onDoubleClick={(e) => { e.stopPropagation(); onRemoveLamp(lamp.id); }}
          >
            <LampModel type={lamp.type} isDragging={draggingLamp?.id === lamp.id} />
          </group>
        ))}
      </group>
    );
  };

  return (
    <group position={[0, trackY, 0]}>
      {systemConfig.layout === 'LINEAL' && renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])}
      {systemConfig.layout === 'RECTANGULAR' && (
        <>
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA L' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA U' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
          {renderTrackSegment(2, width, [width / 2, 0, depth], [0, 0, 0])}
        </>
      )}
    </group>
  );
};

import React from 'react';
import { LampType } from '../types';

interface LampModelProps {
  type: LampType;
  isPreview?: boolean;
  isDragging?: boolean;
}

export const LampModel: React.FC<LampModelProps> = ({ type, isPreview, isDragging }) => {
  const opacity = (isPreview || isDragging) ? 0.4 : 1;
  const color = isPreview ? "#4ade80" : (isDragging ? "#60a5fa" : "#111111");

  if (type === LampType.SPOT_DIRECTIONAL) {
    return (
      <group>
        <mesh position={[0, 0.01, 0]}>
          <boxGeometry args={[0.07, 0.015, 0.015]} />
          <meshStandardMaterial color={color} transparent opacity={opacity} />
        </mesh>
        <mesh position={[0, -0.04, 0]}>
          <cylinderGeometry args={[0.006, 0.006, 0.08]} />
          <meshStandardMaterial color={color} transparent opacity={opacity} />
        </mesh>
        <group position={[0, -0.08, 0]} rotation={[0.4, 0, 0]}>
          <mesh position={[0, -0.04, 0]}>
            <cylinderGeometry args={[0.025, 0.025, 0.1]} />
            <meshStandardMaterial color={color} transparent opacity={opacity} />
          </mesh>
          {!isPreview && !isDragging && (
            <mesh position={[0, -0.09, 0]}>
                <circleGeometry args={[0.02, 32]} rotation={[-Math.PI/2, 0, 0]} />
                <meshStandardMaterial color="#fff" emissive="#fff" emissiveIntensity={1.5} />
            </mesh>
          )}
        </group>
      </group>
    );
  }

  return (
    <group>
      <mesh position={[0, -0.01, 0]}>
        <boxGeometry args={[0.38, 0.02, 0.02]} />
        <meshStandardMaterial color={color} transparent opacity={opacity} />
      </mesh>
      {Array.from({ length: 6 }).map((_, i) => (
        <group key={i} position={[(i - 2.5) * 0.06, -0.025, 0]}>
          <mesh>
            <boxGeometry args={[0.04, 0.008, 0.025]} />
            <meshStandardMaterial color={color} transparent opacity={opacity} />
          </mesh>
          {!isPreview && !isDragging && (
            <mesh position={[0, -0.005, 0]}>
              <boxGeometry args={[0.02, 0.004, 0.015]} />
              <meshStandardMaterial color="#fff" emissive="#fff" emissiveIntensity={0.8} />
            </mesh>
          )}
        </group>
      ))}
    </group>
  );
};

import React, { Suspense, useRef, useState } from 'react';
import { Canvas, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment, Grid, ContactShadows } from '@react-three/drei';
import * as THREE from 'three';
import { ConfigState, LampType } from '../types';
import { EnvironmentContext } from './EnvironmentContext';
import { TrackSystem } from './TrackSystem';

interface Scene3DProps {
  config: ConfigState;
  activeLampType: LampType | null;
  onPlaceLamp: (type: LampType, systemId: string, trackIndex: number, position: number) => void;
  onUpdateLampPos: (systemId: string, lampId: string, newPos: number) => void;
  onRemoveLamp: (systemId: string, id: string) => void;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  sceneGroupRef: React.RefObject<THREE.Group>;
  onUpdateSystemPos: (id: string, pos: [number, number, number]) => void;
  onUpdateObjectPos: (id: string, pos: [number, number, number]) => void;
  onDeleteObject: (id: string) => void;
  onSelectObject: (id: string | null) => void;
  deleteMode: boolean;
}

export const Scene3D: React.FC<Scene3DProps> = ({ 
  config, activeLampType, onPlaceLamp, onUpdateLampPos, onRemoveLamp, canvasRef, sceneGroupRef,
  onUpdateSystemPos, onUpdateObjectPos, onDeleteObject, onSelectObject, deleteMode
}) => {
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [dragType, setDragType] = useState<'system' | 'object' | null>(null);

  const onPointerDown = (e: ThreeEvent<PointerEvent>, id: string, type: 'system' | 'object') => {
    e.stopPropagation();
    if (type === 'object') {
      onSelectObject(id);
      if (deleteMode) {
        onDeleteObject(id);
        return;
      }
    } else {
      onSelectObject(null);
    }
    setDraggingId(id);
    setDragType(type);
  };

  const onPointerUp = () => {
    setDraggingId(null);
    setDragType(null);
  };

  const onPointerMove = (e: ThreeEvent<PointerEvent>) => {
    if (!draggingId || !dragType) return;
    if (dragType === 'system') {
      onUpdateSystemPos(draggingId, [e.point.x, 0, e.point.z]);
    } else {
      onUpdateObjectPos(draggingId, [e.point.x, 0, e.point.z]);
    }
  };

  return (
    <Canvas 
      shadows 
      className="w-full h-full bg-[#fdfdfd]" 
      ref={canvasRef}
      gl={{ preserveDrawingBuffer: true, antialias: true }}
      onPointerMissed={() => onSelectObject(null)}
    >
      <PerspectiveCamera makeDefault position={[6, 4, 6]} fov={35} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 2.15} 
        enableDamping 
        enabled={!draggingId}
        makeDefault
      />

      <ambientLight intensity={0.6} />
      <spotLight position={[5, 10, 5]} angle={0.2} penumbra={1} intensity={1.5} castShadow />

      <Suspense fallback={null}>
        <Environment preset="apartment" />

        <mesh position={[0, config.ceilingHeight, 0]} rotation={[Math.PI / 2, 0, 0]} receiveShadow>
          <planeGeometry args={[50, 50]} />
          <meshStandardMaterial color="#fff" roughness={1} />
        </mesh>

        <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.01, 0]} 
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          visible={false}
        >
          <planeGeometry args={[100, 100]} />
        </mesh>

        <Grid infiniteGrid sectionSize={2} sectionThickness={1} cellSize={0.5} cellThickness={0.5} position={[0, -0.001, 0]} />

        {config.showEnvironment && (
          <EnvironmentContext 
            config={config} 
            onPointerDown={(e, id) => onPointerDown(e, id, 'object')}
            draggingId={draggingId}
            deleteMode={deleteMode}
            selectedObjectId={config.selectedObjectId}
          />
        )}

        <group ref={sceneGroupRef}>
          {config.systems.map((sys) => (
            <group 
              key={sys.id} 
              position={sys.position}
              rotation={[0, sys.rotation, 0]}
              onPointerDown={(e) => onPointerDown(e as any, sys.id, 'system')}
            >
              <TrackSystem 
                config={config} 
                systemId={sys.id}
                systemConfig={sys}
                onTrackClick={(e, trackIdx, pos) => onPlaceLamp(activeLampType!, sys.id, trackIdx, pos)}
                onUpdateLampPos={onUpdateLampPos}
                activeLampType={activeLampType}
                onRemoveLamp={(lampId) => onRemoveLamp(sys.id, lampId)}
                isSelected={config.selectedSystemId === sys.id}
              />
            </group>
          ))}
        </group>

        <ContactShadows position={[0, 0, 0]} opacity={0.3} scale={20} blur={2} far={4} />
      </Suspense>
    </Canvas>
  );
};

