  selectedObjectId: string | null;
}> = ({ config, onPointerDown, draggingId, deleteMode, selectedObjectId }) => {
  return (
    <group>
      {config.envObjects.map((obj) => (
        <group 
          key={obj.id} 
          position={obj.position}
          rotation={obj.rotation}
          onPointerDown={(e) => { e.stopPropagation(); onPointerDown(e, obj.id); }}
        >
          {/* Highlight logic */}
          {(selectedObjectId === obj.id || draggingId === obj.id) && !deleteMode && (
            <mesh position={[0, 0.005, 0]} rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[1.1, 1.15, 64]} />
              <meshBasicMaterial color="#22c55e" transparent opacity={0.4} />
            </mesh>
          )}
          {deleteMode && (
             <mesh position={[0, 0.005, 0]} rotation={[-Math.PI / 2, 0, 0]}>
                <ringGeometry args={[1.1, 1.15, 64]} />
                <meshBasicMaterial color="#ef4444" transparent opacity={0.6} />
             </mesh>
