  onUndo: () => void;
  canUndo: boolean;
  onToggleEnv: () => void;
  deleteMode: boolean;
  setDeleteMode: (val: boolean) => void;
  onEnvTypeChange: (type: EnvironmentType) => void;
  onRotateObject: (id: string) => void;
