export const EnvironmentContext: React.FC<{ 
  config: ConfigState; 
  onPointerDown: (e: ThreeEvent<PointerEvent>, id: string) => void;
  onDoubleClick: (e: ThreeEvent<MouseEvent>, id: string) => void;
  draggingId: string | null;
  deleteMode?: boolean;
  selectedObjectId: string | null;
}> = ({ config, onPointerDown, onDoubleClick, draggingId, deleteMode, selectedObjectId }) => {
  return (
    <group>
      {config.envObjects.map((obj) => (
        <group 
          key={obj.id} 
          position={obj.position}
          rotation={obj.rotation}
          onPointerDown={(e) => { e.stopPropagation(); onPointerDown(e, obj.id); }}
          onDoubleClick={(e) => { e.stopPropagation(); onDoubleClick(e as any, obj.id); }}
        >
          {/* Anillo de Selección */}
          {(selectedObjectId === obj.id || draggingId === obj.id) && !deleteMode && (
            <mesh position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
              <ringGeometry args={[1.1, 1.15, 64]} />
              <meshBasicMaterial color="#22c55e" transparent opacity={0.6} />
            </mesh>
          )}
          {deleteMode && (
             <mesh position={[0, 0.01, 0]} rotation={[-Math.PI / 2, 0, 0]}>
                <ringGeometry args={[1.1, 1.15, 64]} />
                <meshBasicMaterial color="#ef4444" transparent opacity={0.8} />
             </mesh>
          )}
          <group>
            {obj.type === 'sofa' && <Sofa />}
            {obj.type === 'coffeeTable' && <CoffeeTable />}
            {obj.type === 'officeTable' && <OfficeTable />}
            {obj.type === 'sideboard' && <Sideboard />}
            {obj.type === 'loungeChair' && <LoungeChair />}
            {obj.type === 'bookshelf' && <Bookshelf />}
            {obj.type === 'lowCabinet' && <LowCabinet />}
          </group>
        </group>
      ))}
    </group>
  );
};

import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { Scene3D } from './components/Scene3D';
import { Sidebar } from './components/Sidebar';
import { ProductModal } from './components/ProductModal';
import { ConfigState, LayoutType, MountingType, PlacedLamp, PRICING, LampType, EnvironmentType, TrackSystemConfig, EnvironmentObject, EnvObjectType, PRODUCT_DETAILS } from './types';
import * as THREE from 'three';

const LOGO_URL = "https://firebasestorage.googleapis.com/v0/b/clase-22b0d.appspot.com/o/Logo%20EOS.png?alt=media&token=81387693-02f3-424a-939e-4054a1a5b481";

const DEFAULT_HOME: EnvironmentObject[] = [
  { id: 'h1', type: 'sofa', position: [0, 0, -2.5], rotation: [0, 0, 0] },
  { id: 'h2', type: 'coffeeTable', position: [0, 0, -1], rotation: [0, 0, 0] },
  { id: 'h3', type: 'sideboard', position: [2.5, 0, -2.5], rotation: [0, -Math.PI / 2, 0] },
  { id: 'h4', type: 'loungeChair', position: [-2, 0, -1.5], rotation: [0, Math.PI / 4, 0] }
];

const DEFAULT_OFFICE: EnvironmentObject[] = [
  { id: 'o1', type: 'officeTable', position: [0, 0, 0], rotation: [0, 0, 0] },
  { id: 'o2', type: 'officeTable', position: [2.5, 0, 0], rotation: [0, 0, 0] },
  { id: 'o3', type: 'bookshelf', position: [0, 0, -3], rotation: [0, 0, 0] },
  { id: 'o4', type: 'lowCabinet', position: [-2.5, 0, 0], rotation: [0, Math.PI / 2, 0] }
];

const App: React.FC = () => {
  const initialSystemId = Math.random().toString(36).substr(2, 9);
  const [config, setConfig] = useState<ConfigState>({
    environmentType: EnvironmentType.HOME,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    systems: [{
      id: initialSystemId,
      layout: LayoutType.LINEAR,
      mounting: MountingType.SUSPENDIDO,
      width: 3,
      depth: 2,
      position: [0, 0, 0],
      rotation: 0,
      lamps: []
    }],
    selectedSystemId: initialSystemId,
    selectedObjectId: null,
    includeInstallation: false,
    includeShipping: false,
    showEnvironment: true,
    envObjects: [...DEFAULT_HOME]
  });

  const [history, setHistory] = useState<ConfigState[]>([]);
  const [deleteMode, setDeleteMode] = useState(false);
  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<LampType | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  const saveHistory = useCallback((newState: ConfigState) => {
    setHistory(prev => {
      const last = prev[prev.length - 1];
      if (JSON.stringify(last) === JSON.stringify(newState)) return prev;
      return [...prev.slice(-19), newState];
    });
  }, []);

  const handleUndo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setHistory(h => h.slice(0, -1));
      setConfig(prev);
    }
  };

  const updateConfig = (key: keyof ConfigState, value: any) => {
    saveHistory(config);
    setConfig(prev => ({ ...prev, [key]: value }));
  };

  const toggleEnvironment = () => {
    saveHistory(config);
    setConfig(prev => ({ ...prev, showEnvironment: !prev.showEnvironment }));
  };

  const handleEnvironmentTypeChange = (type: EnvironmentType) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      environmentType: type,
      selectedObjectId: null,
      envObjects: type === EnvironmentType.HOME ? [...DEFAULT_HOME] : [...DEFAULT_OFFICE]
    }));
  };

  const quoteData = useMemo(() => {
    let totalRailLength = 0;
    let totalCorners = 0;
    let totalSpots = 0;
    let totalRacks = 0;

    config.systems.forEach(sys => {
      let l = 0; let c = 0;
      switch (sys.layout) {
        case LayoutType.LINEAR: l = sys.width; c = 0; break;
        case LayoutType.RECTANGULAR: l = (sys.width * 2) + (sys.depth * 2); c = 4; break;
        case LayoutType.L_SHAPE: l = sys.width + sys.depth; c = 1; break;
        case LayoutType.U_SHAPE: l = (sys.width * 2) + sys.depth; c = 2; break;
      }
      totalRailLength += l; totalCorners += c;
      totalSpots += sys.lamps.filter(lamp => lamp.type === LampType.SPOT_DIRECTIONAL).length;
      totalRacks += sys.lamps.filter(lamp => lamp.type === LampType.FIXED_RACK).length;
    });

    const railSegments = Math.ceil(totalRailLength / 2);
    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const cornersCost = totalCorners * PRICING.CORNER_PIECE;
    const spotsCost = totalSpots * PRICING.SPOT_DIRECTIONAL;
    const racksCost = totalRacks * PRICING.FIXED_RACK;
    const installationCost = config.includeInstallation ? PRICING.INSTALLATION_BASE + ((totalSpots + totalRacks) * PRICING.INSTALLATION_PER_ITEM) : 0;
    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments, railCost, cornerCount: totalCorners, cornersCost, 
      spotCount: totalSpots, spotsCost, rackCount: totalRacks, racksCost,
      installationCost, shippingCost, 
      subtotal: railCost + cornersCost + spotsCost + racksCost,
      total: railCost + cornersCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const updateSystemPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ 
      ...prev, 
      systems: prev.systems.map(s => s.id === id ? { ...s, position: newPos } : s) 
    }));
  };

  const updateObjectPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ 
      ...prev, 
      envObjects: prev.envObjects.map(o => o.id === id ? { ...o, position: [newPos[0], o.position[1], newPos[2]] } : o) 
    }));
  };

  const deleteObject = (id: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      envObjects: prev.envObjects.filter(o => o.id !== id),
      selectedObjectId: prev.selectedObjectId === id ? null : prev.selectedObjectId
    }));
  };

  const rotateObject = (id: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      envObjects: prev.envObjects.map(o => o.id === id ? { ...o, rotation: [o.rotation[0], o.rotation[1] + Math.PI / 2, o.rotation[2]] } : o)
    }));
  };

  const addLamp = useCallback((type: LampType, systemId: string, trackIndex: number, position: number) => {
    saveHistory(config);
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type, trackIndex, position,
      rotation: type === LampType.SPOT_DIRECTIONAL ? (Math.random() - 0.5) * 2 * Math.PI : 0
    };
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: [...sys.lamps, newLamp] } : sys)
    }));
  }, [config, saveHistory]);

  const removeLamp = useCallback((systemId: string, lampId: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: sys.lamps.filter(l => l.id !== lampId) } : sys)
    }));
  }, [config, saveHistory]);

  const cloneObject = (id: string) => {
    saveHistory(config);
    const obj = config.envObjects.find(o => o.id === id);
    if (!obj) return;
    const newObj: EnvironmentObject = {
      ...obj,
      id: Math.random().toString(36).substr(2, 9),
      position: [obj.position[0] + 0.5, obj.position[1], obj.position[2] + 0.5]
    };
    setConfig(prev => ({ ...prev, envObjects: [...prev.envObjects, newObj] }));
  };

  const handleDownloadPDF = () => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const date = new Date().toLocaleDateString();

    let itemsHtml = `
      <tr><td>Kit Riel Magnético (2m)</td><td>${quoteData.railSegments}</td><td>$${PRICING.RAIL_KIT_2M}</td><td>$${quoteData.railCost}</td></tr>
      ${quoteData.cornerCount > 0 ? `<tr><td>Uniones de Esquina</td><td>${quoteData.cornerCount}</td><td>$${PRICING.CORNER_PIECE}</td><td>$${quoteData.cornersCost}</td></tr>` : ''}
      ${quoteData.spotCount > 0 ? `<tr><td>Spot Bala 12W</td><td>${quoteData.spotCount}</td><td>$${PRICING.SPOT_DIRECTIONAL}</td><td>$${quoteData.spotsCost}</td></tr>` : ''}
      ${quoteData.rackCount > 0 ? `<tr><td>Rack Lineal 8 Luces</td><td>${quoteData.rackCount}</td><td>$${PRICING.FIXED_RACK}</td><td>$${quoteData.racksCost}</td></tr>` : ''}
    `;

    printWindow.document.write(`
      <html>
        <head>
          <title>Cotización EOS Iluminación</title>
          <style>
            body { font-family: 'Inter', sans-serif; padding: 40px; color: #333; }
            .header { display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #000; padding-bottom: 20px; }
            .logo { height: 60px; }
            .title { text-align: right; }
            table { width: 100%; border-collapse: collapse; margin-top: 30px; }
            th { text-align: left; border-bottom: 1px solid #eee; padding: 10px; font-size: 12px; text-transform: uppercase; color: #888; }
            td { padding: 15px 10px; border-bottom: 1px solid #eee; font-size: 14px; }
            .total-section { margin-top: 40px; text-align: right; }
            .total-row { display: flex; justify-content: flex-end; gap: 40px; margin-bottom: 10px; }
            .total-label { font-weight: bold; text-transform: uppercase; font-size: 12px; }
            .grand-total { font-size: 24px; font-weight: bold; margin-top: 10px; border-top: 2px solid #000; padding-top: 10px; }
            .footer { margin-top: 60px; font-size: 10px; color: #999; text-align: center; }
          </style>
        </head>
        <body>
          <div class="header">
            <img src="${LOGO_URL}" class="logo" />
            <div class="title">
              <h1 style="margin:0; font-weight:300;">COTIZACIÓN FORMAL</h1>
              <p style="margin:5px 0 0 0; color:#888;">Fecha: ${date}</p>
            </div>
          </div>
          <table>
            <thead>
              <tr><th>Descripción del Componente</th><th>Cant.</th><th>P. Unitario</th><th>Subtotal</th></tr>
            </thead>
            <tbody>
              ${itemsHtml}
            </tbody>
          </table>
          <div class="total-section">
            <div class="total-row"><span class="total-label">Subtotal Productos</span><span>$${quoteData.subtotal}</span></div>
            ${config.includeInstallation ? `<div class="total-row"><span class="total-label">Servicio de Instalación</span><span>$${quoteData.installationCost}</span></div>` : ''}
            ${config.includeShipping ? `<div class="total-row"><span class="total-label">Logística y Transporte</span><span>$${quoteData.shippingCost}</span></div>` : ''}
            <div class="grand-total"><span class="total-label" style="margin-right:20px">Total Neto USD</span> $${quoteData.total.toLocaleString()}</div>
          </div>
          <div class="footer">
            <p>EOS Iluminación Profesional - Sistemas Magnéticos 48V de Alta Gama</p>
            <p>Válido por 15 días a partir de la fecha de emisión.</p>
          </div>
          <script>window.onload = () => { window.print(); window.close(); }</script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const handleExport3D = async () => {
    if (!sceneGroupRef.current) return;
    const { ColladaExporter } = await import('three/examples/jsm/exporters/ColladaExporter.js');
    const exporter = new ColladaExporter();
    exporter.parse(sceneGroupRef.current, (result) => {
      const blob = new Blob([result.data], { type: 'text/xml' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `eos_iluminacion_3d.dae`;
      link.click();
    }, { version: '1.4.1' });
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden relative">
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          canvasRef={canvasRef}
          sceneGroupRef={sceneGroupRef}
          onUpdateSystemPos={updateSystemPosition}
          onUpdateObjectPos={updateObjectPosition}
          onCloneObject={cloneObject}
          onDeleteObject={deleteObject}
          onSelectObject={(id) => setConfig(prev => ({ ...prev, selectedObjectId: id }))}
          deleteMode={deleteMode}
        />
        <div className="absolute bottom-8 left-8 w-48 z-10">
          <img 
            src={LOGO_URL} 
            alt="EOS Logo" 
            className="w-full h-auto drop-shadow-md" 
            crossOrigin="anonymous"
          />
        </div>
      </div>
      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        updateConfig={updateConfig}
        quoteData={quoteData}
        activeLampType={activeLampType} 
        setActiveLampType={setActiveLampType}
        onDownloadPDF={handleDownloadPDF}
        onExport3D={handleExport3D}
        onProductDetail={setSelectedProduct}
        logoUrl={LOGO_URL}
        onUndo={handleUndo}
        canUndo={history.length > 0}
        onToggleEnv={toggleEnvironment}
        deleteMode={deleteMode}
        setDeleteMode={setDeleteMode}
        onEnvTypeChange={handleEnvironmentTypeChange}
        onRotateObject={rotateObject}
      />
      <ProductModal productType={selectedProduct} onClose={() => setSelectedProduct(null)} />
    </div>
  );
};

export default App;

import React from 'react';
import { ConfigState, LayoutType, LampType, MountingType, EnvironmentType, PRICING, TrackSystemConfig } from '../types';

interface SidebarProps {
  config: ConfigState;
  setConfig: React.Dispatch<React.SetStateAction<ConfigState>>;
  updateConfig: (key: keyof ConfigState, value: any) => void;
  quoteData: any;
  activeLampType: LampType | null;
  setActiveLampType: (type: LampType | null) => void;
  onDownloadPDF: () => void;
  onExport3D: () => void;
  onProductDetail: (type: LampType) => void;
  logoUrl: string;
  onUndo: () => void;
  canUndo: boolean;
  onToggleEnv: () => void;
  deleteMode: boolean;
  setDeleteMode: (val: boolean) => void;
  onEnvTypeChange: (type: EnvironmentType) => void;
  onRotateObject: (id: string) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  config, setConfig, updateConfig, quoteData, activeLampType, setActiveLampType, 
  onDownloadPDF, onExport3D, onProductDetail, logoUrl, onUndo, canUndo, 
  onToggleEnv, deleteMode, setDeleteMode, onEnvTypeChange, onRotateObject
}) => {
  const selectedSystem = config.systems.find(s => s.id === config.selectedSystemId);
  const selectedObject = config.envObjects.find(o => o.id === config.selectedObjectId);

  const updateSelectedSystem = (key: keyof TrackSystemConfig, value: any) => {
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(s => s.id === config.selectedSystemId ? { ...s, [key]: value } : s)
    }));
  };

  const addNewSystem = () => {
    const id = Math.random().toString(36).substr(2, 9);
    setConfig(prev => ({
      ...prev,
      systems: [...prev.systems, {
        id, layout: LayoutType.LINEAR, mounting: MountingType.SUSPENDIDO,
        width: 3, depth: 2, position: [0, 0, 0], rotation: 0, lamps: []
      }],
      selectedSystemId: id
    }));
  };

  const rotateSystem = () => {
    if (selectedSystem) {
      updateSelectedSystem('rotation', (selectedSystem.rotation || 0) + Math.PI / 2);
    }
  };

  return (
    <div className="w-[340px] bg-white border-l flex flex-col h-full z-20 text-[10px] shadow-2xl overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b flex items-center justify-between bg-white shrink-0">
        <div className="flex items-center gap-3">
          <img src={logoUrl} alt="EOS" className="h-8 w-auto object-contain" crossOrigin="anonymous" />
          <h1 className="font-bold uppercase tracking-tighter text-gray-900 leading-tight">
            Configurador <br/> <span className="font-light text-gray-400 text-[8px]">EOS Iluminación</span>
          </h1>
        </div>
        <button 
          onClick={onUndo} 
          disabled={!canUndo}
          className={`p-2 rounded-full border transition-all ${canUndo ? 'border-gray-300 text-black hover:bg-gray-100' : 'border-gray-100 text-gray-200 cursor-not-allowed'}`}
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 10h10a8 8 0 018 8v2M3 10l6 6m-6-6l6-6" /></svg>
        </button>
      </div>

      <div className="p-4 space-y-6 overflow-y-auto flex-1 scrollbar-hide">
        {/* Configuración Técnica Global */}
        <section className="space-y-4">
          <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Configuración Técnica</span>
          <div className="space-y-4 p-4 bg-gray-50 rounded-2xl border border-gray-100">
            <div className="space-y-3">
              <div className="flex flex-col gap-1.5">
                <div className="flex justify-between items-center">
                  <span className="text-[7px] uppercase font-bold text-gray-500">Altura del Techo</span>
                  <span className="font-bold text-[9px]">{config.ceilingHeight.toFixed(1)}m</span>
                </div>
                <input 
                  type="range" min="2.2" max="5" step="0.1" 
                  value={config.ceilingHeight} 
                  onChange={e => updateConfig('ceilingHeight', parseFloat(e.target.value))} 
                  className="w-full accent-black h-1" 
                />
              </div>
              <div className="flex flex-col gap-1.5">
                <div className="flex justify-between items-center">
                  <span className="text-[7px] uppercase font-bold text-gray-500">Cuelgue Riel</span>
                  <span className="font-bold text-[9px]">{config.suspensionHeight.toFixed(1)}m</span>
                </div>
                <input 
                  type="range" min="0" max="2" step="0.1" 
                  value={config.suspensionHeight} 
                  onChange={e => updateConfig('suspensionHeight', parseFloat(e.target.value))} 
                  className="w-full accent-black h-1" 
                />
              </div>
            </div>
          </div>
        </section>

        {/* Entorno */}
        <section className="space-y-3">
          <div className="flex items-center justify-between">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Entorno</span>
            <div className="flex gap-1">
              <button 
                onClick={onToggleEnv} 
                className={`px-3 py-1 rounded-full border text-[7px] font-bold transition-all ${config.showEnvironment ? 'bg-[#22c55e] border-[#22c55e] text-white' : 'bg-white text-gray-400 border-gray-200'}`}
              >
                {config.showEnvironment ? 'VISIBLE' : 'OCULTO'}
              </button>
              <button 
                onClick={() => setDeleteMode(!deleteMode)} 
                className={`px-3 py-1 rounded-full border text-[7px] font-bold transition-all ${deleteMode ? 'bg-[#ef4444] border-[#ef4444] text-white' : 'bg-white text-gray-400 border-gray-200'}`}
              >
                BORRAR
              </button>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-2">
            {Object.values(EnvironmentType).map(type => (
              <button 
                key={type} 
                onClick={() => onEnvTypeChange(type)}
                className={`py-2 border rounded-lg uppercase font-bold text-[8px] transition-all ${config.environmentType === type ? 'bg-black text-white border-black' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-200'}`}
              >
                {type}
              </button>
            ))}
          </div>
          {selectedObject && (
            <button 
              onClick={() => onRotateObject(selectedObject.id)}
              className="w-full py-2 bg-gray-50 border border-gray-200 rounded-lg uppercase font-bold text-[7px] hover:border-black active:bg-gray-200 transition-all flex items-center justify-center gap-2"
            >
              Rotar Objeto Seleccionado 90° ↻
            </button>
          )}
        </section>

        {/* Sistemas de Riel */}
        <section className="space-y-3 pt-4 border-t border-gray-50">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Sistemas de Riel</span>
            <button onClick={addNewSystem} className="bg-black text-white font-bold uppercase text-[7px] px-2 py-1 rounded-full hover:scale-105 transition-transform">+ Nuevo</button>
          </div>
          <div className="flex gap-1 overflow-x-auto pb-1 scrollbar-hide">
            {config.systems.map((s, i) => (
              <button 
                key={s.id} 
                onClick={() => updateConfig('selectedSystemId', s.id)} 
                className={`px-4 py-2 border rounded-full text-[8px] uppercase font-bold transition-all shrink-0 ${config.selectedSystemId === s.id ? 'bg-black text-white border-black shadow-md' : 'bg-white text-gray-400 border-gray-100 hover:border-gray-300'}`}
              >
                Sistema {i + 1}
              </button>
            ))}
          </div>

          {selectedSystem && (
            <div className="space-y-4 p-4 bg-gray-50 rounded-2xl border border-gray-100">
              <div className="grid grid-cols-2 gap-1.5">
                {Object.values(LayoutType).map(v => (
                  <button key={v} onClick={() => updateSelectedSystem('layout', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] transition-all ${selectedSystem.layout === v ? 'bg-black text-white border-black' : 'bg-white text-gray-400 border-gray-100'}`}>{v}</button>
                ))}
              </div>
              <div className="grid grid-cols-3 gap-1.5">
                {Object.values(MountingType).map(v => (
                  <button key={v} onClick={() => updateSelectedSystem('mounting', v)} className={`py-1.5 border rounded-lg uppercase font-bold text-[7px] transition-all ${selectedSystem.mounting === v ? 'bg-black text-white border-black' : 'bg-white text-gray-400 border-gray-100'}`}>{v}</button>
                ))}
              </div>
              <div className="space-y-3">
                <div className="flex items-center gap-3">
                  <span className="w-12 text-[7px] uppercase font-bold text-gray-400">Ancho</span>
                  <input type="range" min="1" max="10" step="0.5" value={selectedSystem.width} onChange={e => updateSelectedSystem('width', parseFloat(e.target.value))} className="flex-1 accent-black h-1" />
                  <span className="w-8 text-right font-bold text-[9px]">{selectedSystem.width}m</span>
                </div>
                {selectedSystem.layout !== LayoutType.LINEAR && (
                  <div className="flex items-center gap-3">
                    <span className="w-12 text-[7px] uppercase font-bold text-gray-400">Fondo</span>
                    <input type="range" min="1" max="10" step="0.5" value={selectedSystem.depth} onChange={e => updateSelectedSystem('depth', parseFloat(e.target.value))} className="flex-1 accent-black h-1" />
                    <span className="w-8 text-right font-bold text-[9px]">{selectedSystem.depth}m</span>
                  </div>
                )}
              </div>
              <button onClick={rotateSystem} className="w-full py-2 bg-white border border-gray-200 rounded-lg uppercase font-bold text-[7px] hover:border-black transition-all flex items-center justify-center gap-2 active:scale-95">
                 Rotar Riel 90° ↻
              </button>
            </div>
          )}
        </section>

        {/* Luminarias */}
        <section className="space-y-3">
          <div className="flex justify-between items-center">
            <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Luminarias</span>
            {activeLampType && <button onClick={() => setActiveLampType(null)} className="text-red-500 font-bold uppercase text-[7px] animate-pulse">● Soltar</button>}
          </div>
          <div className="grid grid-cols-2 gap-3">
            {[LampType.SPOT_DIRECTIONAL, LampType.FIXED_RACK].map(type => (
              <button key={type} onClick={() => setActiveLampType(type)} className={`flex flex-col p-3 border rounded-2xl transition-all ${activeLampType === type ? 'border-black bg-gray-50 ring-1 ring-black shadow-lg' : 'border-gray-100 hover:border-gray-300'}`}>
                <div className="flex justify-between items-center mb-2 w-full">
                  <div className={`w-6 h-6 rounded-full ${activeLampType === type ? 'bg-[#22c55e]' : 'bg-black'}`} />
                  <div onClick={(e) => { e.stopPropagation(); onProductDetail(type); }} className="w-5 h-5 flex items-center justify-center text-[7px] bg-gray-100 rounded-full hover:bg-black hover:text-white border border-transparent">i</div>
                </div>
                <p className="font-bold text-[8px] uppercase">{type === LampType.SPOT_DIRECTIONAL ? 'Spot Bala 12W' : 'Rack 8 Luces'}</p>
                <p className="text-[8px] text-gray-400 font-medium">${type === LampType.SPOT_DIRECTIONAL ? PRICING.SPOT_DIRECTIONAL : PRICING.FIXED_RACK}.00</p>
              </button>
            ))}
          </div>
        </section>

        {/* Cotización Real-Time Simplificada */}
        <section className="space-y-3 border-t pt-4">
          <span className="uppercase font-bold text-gray-400 tracking-widest text-[7px]">Detalle de Cotización</span>
          <div className="bg-gray-50 rounded-2xl p-4 border border-gray-100 space-y-2">
            <div className="flex justify-between items-center text-[8px] text-gray-500 uppercase font-bold">
              <span>Componente</span>
              <span>Total</span>
            </div>
            <div className="space-y-1">
              <div className="flex justify-between text-[9px]">
                <span className="text-gray-600">Kit Riel x{quoteData.railSegments}</span>
                <span className="font-bold">${quoteData.railCost}</span>
              </div>
              {quoteData.cornerCount > 0 && (
                <div className="flex justify-between text-[9px]">
                  <span className="text-gray-600">Uniones x{quoteData.cornerCount}</span>
                  <span className="font-bold">${quoteData.cornersCost}</span>
                </div>
              )}
              {quoteData.spotCount > 0 && (
                <div className="flex justify-between text-[9px]">
                  <span className="text-gray-600">Spot Bala x{quoteData.spotCount}</span>
                  <span className="font-bold">${quoteData.spotsCost}</span>
                </div>
              )}
              {quoteData.rackCount > 0 && (
                <div className="flex justify-between text-[9px]">
                  <span className="text-gray-600">Rack Lineal x{quoteData.rackCount}</span>
                  <span className="font-bold">${quoteData.racksCost}</span>
                </div>
              )}
            </div>
          </div>

          <div className="space-y-2">
            <label className="flex items-center justify-between p-3 rounded-xl bg-gray-50 border border-gray-100 cursor-pointer hover:border-gray-300 transition-colors">
              <div className="flex items-center gap-3">
                <input type="checkbox" checked={config.includeInstallation} onChange={e => updateConfig('includeInstallation', e.target.checked)} className="w-4 h-4 accent-black rounded" />
                <span className="font-bold text-[8px] uppercase tracking-wider text-gray-700">Instalación</span>
              </div>
              <span className="font-bold text-[9px] text-gray-400">${quoteData.installationCost}</span>
            </label>
            <label className="flex items-center justify-between p-3 rounded-xl bg-gray-50 border border-gray-100 cursor-pointer hover:border-gray-300 transition-colors">
              <div className="flex items-center gap-3">
                <input type="checkbox" checked={config.includeShipping} onChange={e => updateConfig('includeShipping', e.target.checked)} className="w-4 h-4 accent-black rounded" />
                <span className="font-bold text-[8px] uppercase tracking-wider text-gray-700">Transporte</span>
              </div>
              <span className="font-bold text-[9px] text-gray-400">${quoteData.shippingCost}</span>
            </label>
          </div>

          <div className="bg-black text-white p-5 rounded-3xl shadow-xl">
            <div className="flex justify-between items-center">
              <span className="text-gray-400 uppercase tracking-widest text-[8px] font-bold">Total Presupuesto</span>
              <span className="text-2xl font-light">${quoteData.total.toLocaleString()}</span>
            </div>
          </div>
        </section>
      </div>

      <div className="p-4 bg-white border-t shrink-0">
        <button onClick={onDownloadPDF} className="w-full py-4 bg-black text-white font-bold uppercase text-[9px] tracking-widest rounded-xl hover:bg-gray-800 transition-all shadow-lg active:scale-98">
          Descargar PDF Formal
        </button>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { Scene3D } from './components/Scene3D';
import { Sidebar } from './components/Sidebar';
import { ProductModal } from './components/ProductModal';
import { ConfigState, LayoutType, MountingType, PlacedLamp, PRICING, LampType, EnvironmentType, TrackSystemConfig, EnvironmentObject, EnvObjectType, PRODUCT_DETAILS } from './types';
import * as THREE from 'three';

const LOGO_URL = "https://firebasestorage.googleapis.com/v0/b/clase-22b0d.appspot.com/o/Logo%20EOS.png?alt=media&token=81387693-02f3-424a-939e-4054a1a5b481";

const DEFAULT_HOME: EnvironmentObject[] = [
  { id: 'h1', type: 'sofa', position: [0, 0, -2.5], rotation: [0, 0, 0] },
  { id: 'h2', type: 'coffeeTable', position: [0, 0, -1], rotation: [0, 0, 0] },
  { id: 'h3', type: 'sideboard', position: [2.5, 0, -2.5], rotation: [0, -Math.PI / 2, 0] },
  { id: 'h4', type: 'loungeChair', position: [-2, 0, -1.5], rotation: [0, Math.PI / 4, 0] }
];

const DEFAULT_OFFICE: EnvironmentObject[] = [
  { id: 'o1', type: 'officeTable', position: [0, 0, 0], rotation: [0, 0, 0] },
  { id: 'o2', type: 'officeTable', position: [2.5, 0, 0], rotation: [0, 0, 0] },
  { id: 'o3', type: 'bookshelf', position: [0, 0, -3], rotation: [0, 0, 0] },
  { id: 'o4', type: 'lowCabinet', position: [-2.5, 0, 0], rotation: [0, Math.PI / 2, 0] }
];

const App: React.FC = () => {
  const initialSystemId = Math.random().toString(36).substr(2, 9);
  const [config, setConfig] = useState<ConfigState>({
    environmentType: EnvironmentType.HOME,
    ceilingHeight: 3,
    suspensionHeight: 0.6,
    systems: [{
      id: initialSystemId,
      layout: LayoutType.LINEAR,
      mounting: MountingType.SUSPENDIDO,
      width: 3,
      depth: 2,
      position: [0, 0, 0],
      rotation: 0,
      lamps: []
    }],
    selectedSystemId: initialSystemId,
    selectedObjectId: null,
    includeInstallation: false,
    includeShipping: false,
    showEnvironment: true,
    envObjects: [...DEFAULT_HOME]
  });

  const [history, setHistory] = useState<ConfigState[]>([]);
  const [deleteMode, setDeleteMode] = useState(false);
  const [activeLampType, setActiveLampType] = useState<LampType | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<LampType | null>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  const saveHistory = useCallback((newState: ConfigState) => {
    setHistory(prev => {
      const last = prev[prev.length - 1];
      if (JSON.stringify(last) === JSON.stringify(newState)) return prev;
      return [...prev.slice(-19), newState];
    });
  }, []);

  const handleUndo = () => {
    if (history.length > 0) {
      const prev = history[history.length - 1];
      setHistory(h => h.slice(0, -1));
      setConfig(prev);
    }
  };

  const updateConfig = (key: keyof ConfigState, value: any) => {
    saveHistory(config);
    setConfig(prev => ({ ...prev, [key]: value }));
  };

  const toggleEnvironment = () => {
    saveHistory(config);
    setConfig(prev => ({ ...prev, showEnvironment: !prev.showEnvironment }));
  };

  const handleEnvironmentTypeChange = (type: EnvironmentType) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      environmentType: type,
      selectedObjectId: null,
      envObjects: type === EnvironmentType.HOME ? [...DEFAULT_HOME] : [...DEFAULT_OFFICE]
    }));
  };

  const quoteData = useMemo(() => {
    let totalRailLength = 0;
    let totalCorners = 0;
    let totalSpots = 0;
    let totalRacks = 0;

    config.systems.forEach(sys => {
      let l = 0; let c = 0;
      switch (sys.layout) {
        case LayoutType.LINEAR: l = sys.width; c = 0; break;
        case LayoutType.RECTANGULAR: l = (sys.width * 2) + (sys.depth * 2); c = 4; break;
        case LayoutType.L_SHAPE: l = sys.width + sys.depth; c = 1; break;
        case LayoutType.U_SHAPE: l = (sys.width * 2) + sys.depth; c = 2; break;
      }
      totalRailLength += l; totalCorners += c;
      totalSpots += sys.lamps.filter(lamp => lamp.type === LampType.SPOT_DIRECTIONAL).length;
      totalRacks += sys.lamps.filter(lamp => lamp.type === LampType.FIXED_RACK).length;
    });

    const railSegments = Math.ceil(totalRailLength / 2);
    const railCost = railSegments * PRICING.RAIL_KIT_2M;
    const cornersCost = totalCorners * PRICING.CORNER_PIECE;
    const spotsCost = totalSpots * PRICING.SPOT_DIRECTIONAL;
    const racksCost = totalRacks * PRICING.FIXED_RACK;
    const installationCost = config.includeInstallation ? PRICING.INSTALLATION_BASE + ((totalSpots + totalRacks) * PRICING.INSTALLATION_PER_ITEM) : 0;
    const shippingCost = config.includeShipping ? PRICING.SHIPPING : 0;

    return {
      railSegments, railCost, cornerCount: totalCorners, cornersCost, 
      spotCount: totalSpots, spotsCost, rackCount: totalRacks, racksCost,
      installationCost, shippingCost, 
      subtotal: railCost + cornersCost + spotsCost + racksCost,
      total: railCost + cornersCost + spotsCost + racksCost + installationCost + shippingCost
    };
  }, [config]);

  const updateSystemPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ 
      ...prev, 
      systems: prev.systems.map(s => s.id === id ? { ...s, position: newPos } : s) 
    }));
  };

  const updateObjectPosition = (id: string, newPos: [number, number, number]) => {
    setConfig(prev => ({ 
      ...prev, 
      envObjects: prev.envObjects.map(o => o.id === id ? { ...o, position: [newPos[0], o.position[1], newPos[2]] } : o) 
    }));
  };

  const handleUpdateLampPos = useCallback((systemId: string, lampId: string, newPos: number) => {
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? {
        ...sys,
        lamps: sys.lamps.map(l => l.id === lampId ? { ...l, position: Math.max(0, Math.min(1, newPos)) } : l)
      } : sys)
    }));
  }, []);

  const deleteObject = (id: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      envObjects: prev.envObjects.filter(o => o.id !== id),
      selectedObjectId: prev.selectedObjectId === id ? null : prev.selectedObjectId
    }));
  };

  const rotateObject = (id: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      envObjects: prev.envObjects.map(o => o.id === id ? { ...o, rotation: [o.rotation[0], o.rotation[1] + Math.PI / 2, o.rotation[2]] } : o)
    }));
  };

  const addLamp = useCallback((type: LampType, systemId: string, trackIndex: number, position: number) => {
    saveHistory(config);
    const newLamp: PlacedLamp = {
      id: Math.random().toString(36).substr(2, 9),
      type, trackIndex, position,
      rotation: type === LampType.SPOT_DIRECTIONAL ? (Math.random() - 0.5) * 2 * Math.PI : 0
    };
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: [...sys.lamps, newLamp] } : sys)
    }));
  }, [config, saveHistory]);

  const removeLamp = useCallback((systemId: string, lampId: string) => {
    saveHistory(config);
    setConfig(prev => ({
      ...prev,
      systems: prev.systems.map(sys => sys.id === systemId ? { ...sys, lamps: sys.lamps.filter(l => l.id !== lampId) } : sys)
    }));
  }, [config, saveHistory]);

  const cloneObject = (id: string) => {
    saveHistory(config);
    const obj = config.envObjects.find(o => o.id === id);
    if (!obj) return;
    const newObj: EnvironmentObject = {
      ...obj,
      id: Math.random().toString(36).substr(2, 9),
      position: [obj.position[0] + 0.5, obj.position[1], obj.position[2] + 0.5]
    };
    setConfig(prev => ({ ...prev, envObjects: [...prev.envObjects, newObj] }));
  };

  const handleDownloadPDF = () => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const date = new Date().toLocaleDateString();

    let itemsHtml = `
      <tr><td>Kit Riel Magnético (2m)</td><td>${quoteData.railSegments}</td><td>$${PRICING.RAIL_KIT_2M}</td><td>$${quoteData.railCost}</td></tr>
      ${quoteData.cornerCount > 0 ? `<tr><td>Uniones de Esquina</td><td>${quoteData.cornerCount}</td><td>$${PRICING.CORNER_PIECE}</td><td>$${quoteData.cornersCost}</td></tr>` : ''}
      ${quoteData.spotCount > 0 ? `<tr><td>Spot Bala 12W</td><td>${quoteData.spotCount}</td><td>$${PRICING.SPOT_DIRECTIONAL}</td><td>$${quoteData.spotsCost}</td></tr>` : ''}
      ${quoteData.rackCount > 0 ? `<tr><td>Rack Lineal 8 Luces</td><td>${quoteData.rackCount}</td><td>$${PRICING.FIXED_RACK}</td><td>$${quoteData.racksCost}</td></tr>` : ''}
    `;

    printWindow.document.write(`
      <html>
        <head>
          <title>Cotización EOS Iluminación</title>
          <style>
            body { font-family: 'Inter', sans-serif; padding: 40px; color: #333; }
            .header { display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #000; padding-bottom: 20px; }
            .logo { height: 60px; }
            .title { text-align: right; }
            table { width: 100%; border-collapse: collapse; margin-top: 30px; }
            th { text-align: left; border-bottom: 1px solid #eee; padding: 10px; font-size: 12px; text-transform: uppercase; color: #888; }
            td { padding: 15px 10px; border-bottom: 1px solid #eee; font-size: 14px; }
            .total-section { margin-top: 40px; text-align: right; }
            .total-row { display: flex; justify-content: flex-end; gap: 40px; margin-bottom: 10px; }
            .total-label { font-weight: bold; text-transform: uppercase; font-size: 12px; }
            .grand-total { font-size: 24px; font-weight: bold; margin-top: 10px; border-top: 2px solid #000; padding-top: 10px; }
            .footer { margin-top: 60px; font-size: 10px; color: #999; text-align: center; }
          </style>
        </head>
        <body>
          <div class="header">
            <img src="${LOGO_URL}" class="logo" />
            <div class="title">
              <h1 style="margin:0; font-weight:300;">COTIZACIÓN FORMAL</h1>
              <p style="margin:5px 0 0 0; color:#888;">Fecha: ${date}</p>
            </div>
          </div>
          <table>
            <thead>
              <tr><th>Descripción del Componente</th><th>Cant.</th><th>P. Unitario</th><th>Subtotal</th></tr>
            </thead>
            <tbody>
              ${itemsHtml}
            </tbody>
          </table>
          <div class="total-section">
            <div class="total-row"><span class="total-label">Subtotal Productos</span><span>$${quoteData.subtotal}</span></div>
            ${config.includeInstallation ? `<div class="total-row"><span class="total-label">Servicio de Instalación</span><span>$${quoteData.installationCost}</span></div>` : ''}
            ${config.includeShipping ? `<div class="total-row"><span class="total-label">Logística y Transporte</span><span>$${quoteData.shippingCost}</span></div>` : ''}
            <div class="grand-total"><span class="total-label" style="margin-right:20px">Total Neto USD</span> $${quoteData.total.toLocaleString()}</div>
          </div>
          <div class="footer">
            <p>EOS Iluminación Profesional - Sistemas Magnéticos 48V de Alta Gama</p>
            <p>Válido por 15 días a partir de la fecha de emisión.</p>
          </div>
          <script>window.onload = () => { window.print(); window.close(); }</script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const handleExport3D = async () => {
    if (!sceneGroupRef.current) return;
    const { ColladaExporter } = await import('three/examples/jsm/exporters/ColladaExporter.js');
    const exporter = new ColladaExporter();
    exporter.parse(sceneGroupRef.current, (result) => {
      const blob = new Blob([result.data], { type: 'text/xml' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `eos_iluminacion_3d.dae`;
      link.click();
    }, { version: '1.4.1' });
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 overflow-hidden relative">
      <div className="flex-1 relative cursor-crosshair">
        <Scene3D 
          config={config} 
          activeLampType={activeLampType}
          onPlaceLamp={addLamp}
          onRemoveLamp={removeLamp}
          onUpdateLampPos={handleUpdateLampPos}
          canvasRef={canvasRef}
          sceneGroupRef={sceneGroupRef}
          onUpdateSystemPos={updateSystemPosition}
          onUpdateObjectPos={updateObjectPosition}
          onCloneObject={cloneObject}
          onDeleteObject={deleteObject}
          onSelectObject={(id) => setConfig(prev => ({ ...prev, selectedObjectId: id }))}
          deleteMode={deleteMode}
        />
        <div className="absolute bottom-8 left-8 w-48 z-10">
          <img 
            src={LOGO_URL} 
            alt="EOS Logo" 
            className="w-full h-auto drop-shadow-md" 
            crossOrigin="anonymous"
          />
        </div>
      </div>
      <Sidebar 
        config={config} 
        setConfig={setConfig} 
        updateConfig={updateConfig}
        quoteData={quoteData}
        activeLampType={activeLampType} 
        setActiveLampType={setActiveLampType}
        onDownloadPDF={handleDownloadPDF}
        onExport3D={handleExport3D}
        onProductDetail={setSelectedProduct}
        logoUrl={LOGO_URL}
        onUndo={handleUndo}
        canUndo={history.length > 0}
        onToggleEnv={toggleEnvironment}
        deleteMode={deleteMode}
        setDeleteMode={setDeleteMode}
        onEnvTypeChange={handleEnvironmentTypeChange}
        onRotateObject={rotateObject}
      />
      <ProductModal productType={selectedProduct} onClose={() => setSelectedProduct(null)} />
    </div>
  );
};

export default App;

import React, { Suspense, useRef, useState } from 'react';
import { Canvas, ThreeEvent } from '@react-three/fiber';
import { OrbitControls, PerspectiveCamera, Environment, Grid, ContactShadows } from '@react-three/drei';
import * as THREE from 'three';
import { ConfigState, LampType } from '../types';
import { EnvironmentContext } from './EnvironmentContext';
import { TrackSystem } from './TrackSystem';

interface Scene3DProps {
  config: ConfigState;
  activeLampType: LampType | null;
  onPlaceLamp: (type: LampType, systemId: string, trackIndex: number, position: number) => void;
  onRemoveLamp: (systemId: string, id: string) => void;
  onUpdateLampPos: (systemId: string, lampId: string, newPos: number) => void;
  canvasRef: React.RefObject<HTMLCanvasElement>;
  sceneGroupRef: React.RefObject<THREE.Group>;
  onUpdateSystemPos: (id: string, pos: [number, number, number]) => void;
  onUpdateObjectPos: (id: string, pos: [number, number, number]) => void;
  onCloneObject: (id: string) => void;
  onDeleteObject: (id: string) => void;
  onSelectObject: (id: string | null) => void;
  deleteMode: boolean;
}

export const Scene3D: React.FC<Scene3DProps> = ({ 
  config, activeLampType, onPlaceLamp, onRemoveLamp, onUpdateLampPos, canvasRef, sceneGroupRef,
  onUpdateSystemPos, onUpdateObjectPos, onCloneObject, onDeleteObject, onSelectObject, deleteMode
}) => {
  const [draggingId, setDraggingId] = useState<string | null>(null);
  const [draggingLampId, setDraggingLampId] = useState<string | null>(null);
  const [dragType, setDragType] = useState<'system' | 'object' | null>(null);

  const onPointerDown = (e: ThreeEvent<PointerEvent>, id: string, type: 'system' | 'object') => {
    e.stopPropagation();
    if (type === 'object') {
      onSelectObject(id);
      if (deleteMode) {
        onDeleteObject(id);
        return;
      }
    } else {
      onSelectObject(null);
    }
    setDraggingId(id);
    setDragType(type);
  };

  const onPointerUp = () => {
    setDraggingId(null);
    setDraggingLampId(null);
    setDragType(null);
  };

  const onPointerMove = (e: ThreeEvent<PointerEvent>) => {
    if (!draggingId || !dragType) return;

    // Proyectar el movimiento sobre el plano XZ (suelo)
    const movePos: [number, number, number] = [e.point.x, 0, e.point.z];

    if (dragType === 'system') {
      onUpdateSystemPos(draggingId, movePos);
    } else {
      onUpdateObjectPos(draggingId, movePos);
    }
  };

  return (
    <Canvas 
      shadows 
      className="w-full h-full bg-[#fdfdfd]" 
      ref={canvasRef}
      gl={{ preserveDrawingBuffer: true, antialias: true }}
      onPointerMissed={() => onSelectObject(null)}
    >
      <PerspectiveCamera makeDefault position={[8, 5, 8]} fov={35} />
      <OrbitControls 
        minPolarAngle={0} 
        maxPolarAngle={Math.PI / 2.15} 
        enableDamping 
        enabled={!draggingId && !draggingLampId}
        makeDefault
      />

      <ambientLight intensity={0.7} />
      <spotLight position={[10, 20, 10]} angle={0.25} penumbra={1} intensity={2.5} castShadow />

      <Suspense fallback={null}>
        <Environment preset="apartment" />

        {/* TECHO: Invisible desde arriba usando THREE.FrontSide y rotación estratégica */}
        <mesh position={[0, config.ceilingHeight, 0]} rotation={[Math.PI / 2, 0, 0]} receiveShadow>
          <planeGeometry args={[100, 100]} />
          <meshStandardMaterial 
            color="#ffffff" 
            side={THREE.FrontSide} 
            roughness={1} 
            transparent={false}
          />
        </mesh>

        {/* Plano invisible para capturar el arrastre */}
        <mesh 
          rotation={[-Math.PI / 2, 0, 0]} 
          position={[0, -0.01, 0]} 
          onPointerMove={onPointerMove}
          onPointerUp={onPointerUp}
          visible={false}
        >
          <planeGeometry args={[200, 200]} />
        </mesh>

        <Grid 
          infiniteGrid 
          fadeDistance={40} 
          fadeStrength={10} 
          sectionSize={2} 
          sectionColor="#cfd8dc" 
          sectionThickness={1.2}
          cellSize={0.5} 
          cellColor="#eceff1"
          cellThickness={0.8}
          position={[0, -0.001, 0]}
        />

        {config.showEnvironment && (
          <EnvironmentContext 
            config={config} 
            onPointerDown={(e, id) => onPointerDown(e, id, 'object')}
            onDoubleClick={(e, id) => onCloneObject(id)}
            draggingId={draggingId}
            deleteMode={deleteMode}
            selectedObjectId={config.selectedObjectId}
          />
        )}

        <group ref={sceneGroupRef}>
          {config.systems.map((sys) => (
            <group 
              key={sys.id} 
              position={sys.position}
              rotation={[0, sys.rotation, 0]}
              onPointerDown={(e) => onPointerDown(e as any, sys.id, 'system')}
            >
              <TrackSystem 
                config={config} 
                systemId={sys.id}
                systemConfig={sys}
                onTrackClick={(e, trackIdx, pos) => onPlaceLamp(activeLampType!, sys.id, trackIdx, pos)}
                onUpdateLampPos={onUpdateLampPos}
                activeLampType={activeLampType}
                onRemoveLamp={(lampId) => onRemoveLamp(sys.id, lampId)}
                isSelected={config.selectedSystemId === sys.id}
                setGlobalDraggingLamp={setDraggingLampId}
              />
            </group>
          ))}
        </group>

        <ContactShadows position={[0, 0, 0]} opacity={0.25} scale={40} blur={2.5} far={8} />
      </Suspense>
    </Canvas>
  );
};

import React, { useState } from 'react';
import * as THREE from 'three';
import { ThreeEvent } from '@react-three/fiber';
import { ConfigState, LampType, TrackSystemConfig, MountingType } from '../types';
import { LampModel } from './LampModels';

interface TrackSystemProps {
  config: ConfigState;
  systemId: string;
  systemConfig: TrackSystemConfig;
  onTrackClick: (e: ThreeEvent<MouseEvent>, trackIndex: number, pos: number) => void;
  onUpdateLampPos: (systemId: string, lampId: string, newPos: number) => void;
  activeLampType: LampType | null;
  onRemoveLamp: (id: string) => void;
  isSelected: boolean;
  setGlobalDraggingLamp: (id: string | null) => void;
}

export const TrackSystem: React.FC<TrackSystemProps> = ({ 
  config, systemId, systemConfig, onTrackClick, onUpdateLampPos, activeLampType, onRemoveLamp, isSelected, setGlobalDraggingLamp
}) => {
  const { mounting, width, depth, lamps } = systemConfig;
  const { ceilingHeight, suspensionHeight } = config;
  const [hoveredTrack, setHoveredTrack] = useState<{ index: number; pos: number } | null>(null);

  // Estado para el arrastre de lámparas: ID y offset local para evitar saltos
  const [draggingLamp, setDraggingLamp] = useState<{ id: string, index: number, offset: number } | null>(null);

  const trackY = mounting === MountingType.SUSPENDIDO ? ceilingHeight - suspensionHeight : (mounting === MountingType.SUPERFICIAL ? ceilingHeight - 0.02 : ceilingHeight + 0.015);
  const railThickness = 0.04;

  const getTensorPositions = (length: number) => {
    const edgeOffset = 0.1; 
    if (length <= 2 * edgeOffset) return [0];
    const positions = [-length / 2 + edgeOffset, length / 2 - edgeOffset];
    if (length > 2.5) positions.push(0);
    return positions;
  };

  const renderTrackSegment = (index: number, length: number, pos: [number, number, number], rot: [number, number, number]) => {
    const tensorOffsets = getTensorPositions(length);

    return (
      <group position={pos} rotation={rot}>
        <mesh 
          onPointerMove={(e) => {
            e.stopPropagation();
            const localPoint = e.point.clone().applyMatrix4(new THREE.Matrix4().copy(e.object.matrixWorld).invert());
            const localX = localPoint.x;
            const normalizedPos = (localX + length / 2) / length;

            // Caso 1: Arrastrando una lámpara existente
            if (draggingLamp && draggingLamp.index === index) {
              const adjustedX = localX + draggingLamp.offset;
              const finalPos = (adjustedX + length / 2) / length;
              onUpdateLampPos(systemId, draggingLamp.id, finalPos);
              return;
            }

            // Caso 2: Previsualización para colocar nueva lámpara
            if (activeLampType) {
              setHoveredTrack({ index, pos: Math.max(0, Math.min(1, normalizedPos)) });
            }
          }}
          onPointerUp={(e) => {
            e.stopPropagation();
            setDraggingLamp(null);
            setGlobalDraggingLamp(null);
          }}
          onPointerOut={() => {
            if (!draggingLamp) setHoveredTrack(null);
          }}
          onClick={(e) => {
             if (activeLampType && hoveredTrack?.index === index && !draggingLamp) {
               e.stopPropagation();
               onTrackClick(e, index, hoveredTrack.pos);
             }
          }}
          position={[0, trackY, 0]}
          castShadow
        >
          <boxGeometry args={[length, railThickness, railThickness]} />
          <meshStandardMaterial color={isSelected ? "#000" : "#111"} roughness={0.9} />
        </mesh>

        {/* Tirantes de suspensión */}
        {mounting === MountingType.SUSPENDIDO && tensorOffsets.map((tx, i) => {
          return (
            <mesh key={i} position={[tx, trackY + suspensionHeight / 2, 0]}>
              <cylinderGeometry args={[0.003, 0.003, suspensionHeight, 8]} />
              <meshStandardMaterial color="#888" />
            </mesh>
          );
        })}

        {/* Previsualización de colocación */}
        {activeLampType && hoveredTrack?.index === index && !draggingLamp && (
          <group position={[hoveredTrack.pos * length - length/2, trackY - railThickness/2, 0]}>
            <LampModel type={activeLampType} isPreview />
          </group>
        )}

        {/* Lámparas colocadas */}
        {lamps.filter(l => l.trackIndex === index).map(lamp => (
          <group 
            key={lamp.id} 
            position={[lamp.position * length - length/2, trackY - railThickness/2, 0]}
            rotation={[0, lamp.rotation, 0]}
            onPointerDown={(e) => {
              e.stopPropagation();
              // Calculamos el offset: posición actual del objeto - posición del ratón en el eje X local
              const localPoint = e.point.clone().applyMatrix4(new THREE.Matrix4().copy(e.object.parent!.matrixWorld).invert());
              const currentX = lamp.position * length - length/2;
              const offset = currentX - localPoint.x;

              setDraggingLamp({ id: lamp.id, index: index, offset: offset });
              setGlobalDraggingLamp(lamp.id);
            }}
            onClick={(e) => {
              // Si no se movió (o fue un clic rápido), permitir borrar si es necesario
              // Aunque el prompt pide solo mejorar el movimiento
            }}
          >
            <LampModel type={lamp.type} />
            {/* Botón de borrado pequeño opcional sobre la lámpara */}
            <mesh 
              position={[0, -0.05, 0.05]} 
              visible={false} 
              onClick={(e) => { e.stopPropagation(); onRemoveLamp(lamp.id); }}
            >
              <sphereGeometry args={[0.05]} />
            </mesh>
          </group>
        ))}
      </group>
    );
  };

  return (
    <group onPointerUp={() => { setDraggingLamp(null); setGlobalDraggingLamp(null); }}>
      {systemConfig.layout === 'LINEAL' && renderTrackSegment(0, width, [0, 0, 0], [0, 0, 0])}
      {systemConfig.layout === 'RECTANGULAR' && (
        <>
          {renderTrackSegment(0, width, [0, 0, depth / 2], [0, 0, 0])}
          {renderTrackSegment(2, width, [0, 0, -depth / 2], [0, 0, 0])}
          {renderTrackSegment(1, depth, [-width / 2, 0, 0], [0, Math.PI / 2, 0])}
          {renderTrackSegment(3, depth, [width / 2, 0, 0], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA L' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
        </>
      )}
      {systemConfig.layout === 'FORMA U' && (
        <>
          {renderTrackSegment(0, width, [width / 2, 0, 0], [0, 0, 0])}
          {renderTrackSegment(1, depth, [width, 0, depth / 2], [0, Math.PI / 2, 0])}
          {renderTrackSegment(2, width, [width / 2, 0, depth], [0, 0, 0])}
        </>
      )}
    </group>
  );
};
